// Returns a readable label for a day's planned cardio, e.g. "Zone 2 Walk + HIIT".
function cardioPlanLabel(plan, dayIdx) {
  const ids = (plan && plan[dayIdx]) || [];
  if (!ids.length) return "";
  return ids.map(id => { const t = CARDIO_TYPES.find(x=>x.id===id); return t ? t.label : id; }).join(" + ");
}

// Zone 2 heart-rate range (fat-burning aerobic zone): 60-70% of estimated max HR.
// Max HR uses the Tanaka formula (208 - 0.7*age), more accurate than 220-age.
function zone2Range(age) {
  const a = parseFloat(age) || 30;
  const maxHR = Math.round(208 - 0.7 * a);
  return { maxHR, low: Math.round(maxHR * 0.60), high: Math.round(maxHR * 0.70) };
}

// Calories burned for a steady session.
function caloriesBurned(activityId, intensityId, minutes, weightLbs) {
  const act = CARDIO_ACTIVITIES.find(a=>a.id===activityId) || CARDIO_ACTIVITIES[0];
  const met = act.mets[intensityId] || act.mets.moderate;
  const kg = lbsToKg(weightLbs);
  const perMin = met * 3.5 * kg / 200;
  return Math.round(perMin * (minutes||0));
}

function pickFocusGroups(profile) {
  const f = profile.focus;
  if (f.includes("Upper")) return { groups:["chest","back","shoulders","arms"], stretch:"upper" };
  if (f.includes("Lower")) return { groups:["glutes","legs","calves"], stretch:"lower" };
  if (f.includes("Core"))  return { groups:["core","glutes","shoulders"], stretch:"lower" };
  return { groups:["chest","back","legs","glutes","shoulders","arms"], stretch:"upper" }; // full body
}

function dayPlan(label, type, focusText, primaryGroups, accessoryGroups, target, opts) {
  // Build exercises to fit the session length: load primary groups heavily, top up from accessories.
  const seen = new Set();
  const workout = [];
  const TARGET = target || 6;
  const rotation = (opts && opts.rotation) || 0; // 0/1/2 → 4-week exercise rotation (sets A/B/C)
  const block = opts && opts.block;              // 2-week intensity block (sets/reps/rest override)

  function addFrom(group, max) {
    const pool = EX[group];
    if (!pool) return;
    // Rotate the pool so each 4-week phase pulls a DIFFERENT slice of lifts for the
    // same muscle (same body part, fresh exercises → dodges adaptation).
    const off = (rotation * 2) % pool.length;
    const ordered = pool.slice(off).concat(pool.slice(0, off));
    for (const ex of ordered) {
      if (workout.length >= TARGET) break;
      if (max <= 0) break;
      if (seen.has(ex.exercise)) continue;
      seen.add(ex.exercise);
      workout.push(ex);
      max--;
    }
  }

  // Spread evenly across the primary groups first
  const primaries = primaryGroups || [];
  const perPrimary = primaries.length ? Math.max(2, Math.ceil(TARGET / primaries.length)) : 0;
  primaries.forEach(g => addFrom(g, perPrimary));

  // Top up with accessory groups until we hit the target
  (accessoryGroups || []).forEach(g => addFrom(g, TARGET));

  // If still short, pull more from the first primary group
  if (workout.length < TARGET && primaries[0]) addFrom(primaries[0], TARGET);

  const out = workout.slice(0, TARGET).map(ex => applyBlock(ex, block));
  return { day:label, type, focus:focusText, workout: out };
}

// Map session length (minutes) to how many exercises fit. ~8-10 min per exercise.
function exercisesForTime(sessionTime) {
  const t = parseInt(sessionTime) || 60;
  if (t <= 30) return 4;
  if (t <= 45) return 5;
  return 6;   // 60+ minutes
}

// Build a 7-day week tailored to the focus.
// Day name helpers
const DAY_NAMES = ["Sunday","Monday","Tuesday","Wednesday","Thursday","Friday","Saturday"];
const DEFAULT_DAYS = [1,2,3,4,5]; // Mon-Fri, used if none chosen

// Build the list of session templates (without day labels) for a given focus + count.
// ── PROGRAM BUILDER ────────────────────────────────────────────────────────────
// Builds the weekly split using science-based frequency principles.
// Core rule: hit each muscle group ~2x/week for optimal hypertrophy.
// Split is determined by day count; session length controls volume (# exercises).
function sessionTemplates(focus, count, goal, gender) {
  const T = (type, focusText, primary, accessory) => ({ type, focusText, primary, accessory });
  const isLower = (focus||"").includes("Lower");
  const isUpper = (focus||"").includes("Upper");
  const isCore  = (focus||"").includes("Core");
  const isFemale = (gender||"") === "Female";

  // ══ FEMALE-TAILORED TEMPLATES ════════════════════════════════════════════════
  // Women's standard programs bias toward glutes, hamstrings and lower body,
  // with shoulders/back for upper-body shape and core for waist definition.
  // This is what makes the women's programs genuinely different from men's.
  if (isFemale) {
    // FEMALE FULL BODY — every session includes glute work; lower-body weighted
    if (!isLower && !isUpper && !isCore) {
      if (count === 1) return [
        T("Total Body Sculpt","Glutes, Legs, Back & Shoulders",["glutes","legs","back","shoulders"],["core","arms"]),
      ];
      if (count === 2) return [
        T("Glutes, Legs & Shoulders","Lower + Shape",["glutes","legs","shoulders"],["core"]),
        T("Glutes, Back & Arms","Posterior + Tone",["glutes","back"],["arms","core"]),
      ];
      if (count === 3) return [
        T("Glutes & Hamstrings","Posterior Focus",["glutes","legs"],["core"]),
        T("Back, Shoulders & Arms","Upper Body Shape",["back","shoulders"],["arms"]),
        T("Glutes, Quads & Calves","Lower Body",["glutes","legs"],["calves","core"]),
      ];
      if (count === 4) return [
        T("Glutes & Hamstrings","Posterior — Day 1",["glutes","legs"],["core"]),
        T("Back & Shoulders","Upper Shape — Day 1",["back","shoulders"],["arms"]),
        T("Glutes & Quads","Lower — Day 2",["glutes","legs"],["calves"]),
        T("Shoulders, Arms & Core","Upper Tone + Waist",["shoulders","arms","core"],["back"]),
      ];
      if (count === 5) return [
        T("Glutes & Hamstrings","Posterior — Day 1",["glutes","legs"],["core"]),
        T("Back & Shoulders","Upper Shape",["back","shoulders"],["arms"]),
        T("Glutes & Quads","Lower — Day 2",["glutes","legs"],["calves"]),
        T("Arms, Shoulders & Core","Tone + Waist",["shoulders","arms","core"],[]),
        T("Glutes & Hip Thrust","Glute Focus — Day 3",["glutes"],["legs","core"]),
      ];
      if (count === 6) return [
        T("Glutes & Hamstrings","Posterior — Day 1",["glutes","legs"],["core"]),
        T("Back & Shoulders","Upper Shape — Day 1",["back","shoulders"],["arms"]),
        T("Glutes & Quads","Lower — Day 2",["glutes","legs"],["calves"]),
        T("Shoulders, Arms & Core","Tone + Waist",["shoulders","arms","core"],[]),
        T("Glutes — Hip Thrust","Glute Focus — Day 3",["glutes"],["core"]),
        T("Back, Arms & Calves","Upper + Lower Detail",["back","arms"],["calves"]),
      ];
      return [
        T("Glutes & Hamstrings","Posterior — Day 1",["glutes","legs"],["core"]),
        T("Back & Shoulders","Upper Shape — Day 1",["back","shoulders"],["arms"]),
        T("Glutes & Quads","Lower — Day 2",["glutes","legs"],["calves"]),
        T("Shoulders, Arms & Core","Tone + Waist",["shoulders","arms","core"],[]),
        T("Glutes — Hip Thrust","Glute Focus — Day 3",["glutes"],["core"]),
        T("Back, Arms & Calves","Upper + Lower Detail",["back","arms"],["calves"]),
        T("Core & Glute Activation","Active Recovery + Waist",["core","glutes"],[]),
      ];
    }

    // FEMALE LOWER BODY — glute-dominant, the most popular women's program
    if (isLower) {
      if (count === 1) return [T("Glutes & Lower Body","Glutes, Hamstrings & Quads",["glutes","legs"],["core","calves"])];
      if (count === 2) return [
        T("Glutes & Hamstrings","Posterior Focus",["glutes","legs"],["core"]),
        T("Glutes & Quads","Glutes + Quad Shape",["glutes","legs"],["calves"]),
      ];
      if (count === 3) return [
        T("Glutes & Hamstrings","Posterior — Hip Hinge",["glutes","legs"],["core"]),
        T("Glutes — Hip Thrust","Glute Builder",["glutes"],["core"]),
        T("Quads, Glutes & Calves","Legs + Shape",["glutes","legs"],["calves"]),
      ];
      if (count === 4) return [
        T("Glutes & Hamstrings","Posterior — Day 1",["glutes","legs"],["core"]),
        T("Glutes — Hip Thrust","Glute Builder — Day 1",["glutes"],["core"]),
        T("Quads & Glutes","Legs + Shape",["glutes","legs"],["calves"]),
        T("Glutes & Abductors","Side Glute + Hips",["glutes"],["legs","core"]),
      ];
      if (count === 5) return [
        T("Glutes & Hamstrings","Posterior — Day 1",["glutes","legs"],["core"]),
        T("Glutes — Hip Thrust","Glute Builder — Day 1",["glutes"],["core"]),
        T("Quads & Glutes","Legs + Shape — Day 1",["glutes","legs"],["calves"]),
        T("Glutes & Abductors","Side Glute + Hips",["glutes"],["legs"]),
        T("Glutes & Hamstrings — Day 2","Posterior + Calves",["glutes","legs"],["calves","core"]),
      ];
      if (count === 6) return [
        T("Glutes & Hamstrings","Posterior — Day 1",["glutes","legs"],["core"]),
        T("Glutes — Hip Thrust","Glute Builder — Day 1",["glutes"],["core"]),
        T("Quads & Glutes","Legs + Shape — Day 1",["glutes","legs"],["calves"]),
        T("Glutes & Abductors","Side Glute + Hips",["glutes"],["legs"]),
        T("Glutes — Hip Thrust — Day 2","Glute Builder",["glutes"],["core"]),
        T("Hamstrings, Glutes & Calves","Posterior + Detail",["glutes","legs"],["calves"]),
      ];
      return [
        T("Glutes & Hamstrings","Posterior — Day 1",["glutes","legs"],["core"]),
        T("Glutes — Hip Thrust","Glute Builder — Day 1",["glutes"],["core"]),
        T("Quads & Glutes","Legs + Shape — Day 1",["glutes","legs"],["calves"]),
        T("Glutes & Abductors","Side Glute + Hips",["glutes"],["legs"]),
        T("Glutes — Hip Thrust — Day 2","Glute Builder",["glutes"],["core"]),
        T("Hamstrings, Glutes & Calves","Posterior + Detail",["glutes","legs"],["calves"]),
        T("Core & Glute Activation","Active Recovery + Waist",["core","glutes"],[]),
      ];
    }

    // FEMALE UPPER BODY — shape & tone focus: shoulders for the hourglass top,
    // back for posture, arms toned, plus core for the waist. Lighter on chest.
    if (isUpper) {
      if (count === 1) return [T("Upper Body Shape","Shoulders, Back & Arms",["shoulders","back"],["arms","core"])];
      if (count === 2) return [
        T("Shoulders & Back","Posture + Shape",["shoulders","back"],["core"]),
        T("Arms & Chest","Tone + Core",["arms","chest"],["core"]),
      ];
      if (count === 3) return [
        T("Shoulders & Back","Shape + Posture",["shoulders","back"],["core"]),
        T("Arms & Core","Tone + Waist",["arms","core"],["shoulders"]),
        T("Back & Chest","Upper Balance",["back","chest"],["arms"]),
      ];
      if (count === 4) return [
        T("Shoulders & Back","Shape — Day 1",["shoulders","back"],["core"]),
        T("Arms & Core","Tone + Waist",["arms","core"],[]),
        T("Back & Shoulders","Shape — Day 2",["back","shoulders"],["arms"]),
        T("Chest, Arms & Core","Upper Tone + Waist",["chest","arms","core"],[]),
      ];
      if (count === 5) return [
        T("Shoulders & Back","Shape — Day 1",["shoulders","back"],["core"]),
        T("Arms & Core","Tone + Waist",["arms","core"],[]),
        T("Back & Shoulders","Shape — Day 2",["back","shoulders"],["arms"]),
        T("Chest & Arms","Upper Tone",["chest","arms"],[]),
        T("Shoulders & Core","Delts + Waist",["shoulders","core"],["arms"]),
      ];
      if (count === 6) return [
        T("Shoulders & Back","Shape — Day 1",["shoulders","back"],["core"]),
        T("Arms & Core","Tone + Waist — Day 1",["arms","core"],[]),
        T("Back & Shoulders","Shape — Day 2",["back","shoulders"],["arms"]),
        T("Chest & Arms","Upper Tone",["chest","arms"],[]),
        T("Shoulders & Core","Delts + Waist",["shoulders","core"],["arms"]),
        T("Back, Arms & Core","Tone + Waist — Day 2",["back","arms","core"],[]),
      ];
      return [
        T("Shoulders & Back","Shape — Day 1",["shoulders","back"],["core"]),
        T("Arms & Core","Tone + Waist — Day 1",["arms","core"],[]),
        T("Back & Shoulders","Shape — Day 2",["back","shoulders"],["arms"]),
        T("Chest & Arms","Upper Tone",["chest","arms"],[]),
        T("Shoulders & Core","Delts + Waist",["shoulders","core"],["arms"]),
        T("Back, Arms & Core","Tone + Waist — Day 2",["back","arms","core"],[]),
        T("Core & Mobility","Active Recovery + Waist",["core"],["glutes"]),
      ];
    }
    // Female CORE falls through to the shared core logic below (already waist-focused)
  }

  // ── FULL BODY / DEFAULT focus ────────────────────────────────────────────────
  if (!isLower && !isUpper && !isCore) {
    if (count === 1) return [
      T("Total Body",         "Chest, Back, Legs & Shoulders",["chest","back","legs","shoulders"],["arms","core"]),
    ];
    if (count === 2) return [
      T("Chest, Shoulders & Legs", "Push Focus",["chest","shoulders","legs"],["arms","core"]),
      T("Back, Glutes & Arms",     "Pull Focus",["back","legs","glutes"],["arms","core"]),
    ];
    if (count === 3) return [
      T("Chest, Shoulders & Triceps","Push — Front of Body",["chest","shoulders"],["arms"]),
      T("Back & Biceps",            "Pull — Back of Body",["back"],["arms"]),
      T("Legs, Glutes & Calves",    "Lower Body",["legs","glutes"],["calves","core"]),
    ];
    if (count === 4) return [
      T("Chest & Back",         "Upper Body — Day 1",["chest","back"],["arms"]),
      T("Quads & Glutes",       "Lower Body — Day 1",["legs","glutes"],["calves"]),
      T("Shoulders & Arms",     "Upper Body — Day 2",["shoulders","arms"],["chest"]),
      T("Hamstrings & Glutes",  "Lower Body — Day 2",["glutes","legs"],["core","calves"]),
    ];
    if (count === 5) return [
      T("Chest, Shoulders & Triceps","Push — Front of Body",["chest","shoulders"],["arms"]),
      T("Back & Biceps",            "Pull — Back of Body",["back"],["arms"]),
      T("Legs, Glutes & Calves",    "Lower Body",["legs","glutes"],["calves"]),
      T("Chest, Back & Shoulders",  "Upper Body",["chest","back","shoulders"],["arms"]),
      T("Quads, Hamstrings & Glutes","Lower Body — Day 2",["legs","glutes"],["core","calves"]),
    ];
    if (count === 6) return [
      T("Chest & Triceps",      "Front of Body — Day 1",["chest"],["arms","shoulders"]),
      T("Back & Biceps",        "Back of Body — Day 1",["back"],["arms"]),
      T("Quads & Calves",       "Lower Body — Day 1",["legs"],["glutes","calves"]),
      T("Shoulders & Chest",    "Front of Body — Day 2",["shoulders","chest"],["arms"]),
      T("Back & Arms",          "Back of Body — Day 2",["back","arms"],[]),
      T("Hamstrings & Glutes",  "Lower Body — Day 2",["glutes","legs"],["core","calves"]),
    ];
    return [
      T("Chest & Triceps",      "Front of Body — Day 1",["chest"],["arms","shoulders"]),
      T("Back & Biceps",        "Back of Body — Day 1",["back"],["arms"]),
      T("Quads & Calves",       "Lower Body — Day 1",["legs"],["glutes","calves"]),
      T("Shoulders & Chest",    "Front of Body — Day 2",["shoulders","chest"],["arms"]),
      T("Back & Arms",          "Back of Body — Day 2",["back","arms"],[]),
      T("Hamstrings & Glutes",  "Lower Body — Day 2",["glutes","legs"],["core","calves"]),
      T("Core & Mobility",      "Active Recovery",["core"],["glutes"]),
    ];
  }

  // ── UPPER BODY focus ─────────────────────────────────────────────────────────
  if (isUpper) {
    if (count === 1) return [T("Full Upper Body","Chest, Back, Shoulders & Arms",["chest","back","shoulders"],["arms"])];
    if (count === 2) return [
      T("Chest & Triceps","Front of Body",["chest"],["arms"]),
      T("Back & Biceps","Back of Body",["back"],["arms"]),
    ];
    if (count === 3) return [
      T("Chest & Triceps","Front of Body",["chest"],["arms"]),
      T("Back & Biceps","Back of Body",["back"],["arms"]),
      T("Shoulders & Arms","Delts, Biceps & Triceps",["shoulders","arms"],[]),
    ];
    if (count === 4) return [
      T("Chest & Triceps","Front of Body — Day 1",["chest"],["arms"]),
      T("Back & Biceps","Back of Body — Day 1",["back"],["arms"]),
      T("Shoulders & Traps","Delts & Traps",["shoulders"],[]),
      T("Arms & Chest","Arms & Upper Pump",["arms","chest"],["shoulders"]),
    ];
    if (count === 5) return [
      T("Chest & Triceps","Front of Body — Day 1",["chest"],["arms"]),
      T("Back & Biceps","Back of Body — Day 1",["back"],["arms"]),
      T("Shoulders & Traps","Delts & Traps",["shoulders"],[]),
      T("Chest & Shoulders","Front of Body — Day 2",["chest","shoulders"],["arms"]),
      T("Back & Arms","Back of Body — Day 2",["back","arms"],[]),
    ];
    if (count === 6) return [
      T("Chest & Triceps","Front of Body — Day 1",["chest"],["arms"]),
      T("Back & Biceps","Back of Body — Day 1",["back"],["arms"]),
      T("Shoulders — Front & Side","Delts Day 1",["shoulders"],[]),
      T("Chest & Arms","Front of Body — Day 2",["chest","arms"],[]),
      T("Back & Rear Delts","Back of Body — Day 2",["back","shoulders"],["arms"]),
      T("Biceps & Triceps","Arms Focus",["arms"],["core"]),
    ];
    return [
      T("Chest & Triceps","Front of Body — Day 1",["chest"],["arms"]),
      T("Back & Biceps","Back of Body — Day 1",["back"],["arms"]),
      T("Shoulders & Traps","Delts & Traps",["shoulders"],[]),
      T("Chest & Shoulders","Front of Body — Day 2",["chest","shoulders"],["arms"]),
      T("Back & Arms","Back of Body — Day 2",["back","arms"],[]),
      T("Biceps & Triceps","Arms Focus",["arms"],[]),
      T("Core & Mobility","Active Recovery",["core"],[]),
    ];
  }

  // ── LOWER BODY focus ─────────────────────────────────────────────────────────
  if (isLower) {
    if (count === 1) return [T("Lower Body","Legs, Glutes & Core",["legs","glutes"],["core","calves"])];
    if (count === 2) return [
      T("Quads & Calves","Quad Focus",["legs"],["calves"]),
      T("Hamstrings & Glutes","Posterior Chain",["glutes","legs"],["core"]),
    ];
    if (count === 3) return [
      T("Glutes & Hamstrings","Posterior Focus",["glutes","legs"],["calves"]),
      T("Quads & Calves","Quad Focus",["legs"],["calves"]),
      T("Glutes & Core","Glute Focus",["glutes"],["core"]),
    ];
    if (count === 4) return [
      T("Glutes & Hamstrings","Posterior — Day 1",["glutes"],["legs"]),
      T("Quads & Calves","Quad Focus — Day 1",["legs"],["calves"]),
      T("Glutes — Hip Thrust","Posterior — Day 2",["glutes"],["core"]),
      T("Hamstrings & Calves","Posterior & Calves",["legs"],["calves","glutes"]),
    ];
    if (count === 5) return [
      T("Glutes & Hamstrings","Posterior — Day 1",["glutes"],["legs"]),
      T("Quads & Calves","Quad Focus — Day 1",["legs"],["calves"]),
      T("Glutes — Hip Thrust","Posterior — Day 2",["glutes"],["core"]),
      T("Quads — Burnout","Quad Focus — Day 2",["legs"],["glutes"]),
      T("Full Lower Body","Complete Lower",["legs","glutes"],["core","calves"]),
    ];
    if (count === 6) return [
      T("Glutes & Hamstrings","Posterior — Day 1",["glutes"],["legs"]),
      T("Quads & Calves","Quad Focus — Day 1",["legs"],["calves"]),
      T("Hamstrings & Glutes — Day 1","Posterior Chain",["legs","glutes"],["core"]),
      T("Glutes — Hip Thrust","Posterior — Day 2",["glutes"],["core"]),
      T("Quads & Calves — Day 2","Quad Focus",["legs"],["calves"]),
      T("Hamstrings & Glutes — Day 2","Posterior Chain",["glutes","legs"],["calves"]),
    ];
    return [
      T("Glutes & Hamstrings","Posterior — Day 1",["glutes"],["legs"]),
      T("Quads & Calves","Quad Focus — Day 1",["legs"],["calves"]),
      T("Hamstrings & Glutes — Day 1","Posterior Chain",["legs","glutes"],["core"]),
      T("Glutes — Hip Thrust","Posterior — Day 2",["glutes"],["core"]),
      T("Quads & Calves — Day 2","Quad Focus",["legs"],["calves"]),
      T("Hamstrings & Glutes — Day 2","Posterior Chain",["glutes","legs"],["calves"]),
      T("Active Recovery","Core & Mobility",["core"],["glutes"]),
    ];
  }

  // ── CORE focus ───────────────────────────────────────────────────────────────
  if (count === 1) return [T("Core & Strength","Full Core & Compound",["core","shoulders","back"],["glutes"])];
  if (count === 2) return [
    T("Core & Push","Abs, Chest & Shoulders",["core","chest","shoulders"],["arms"]),
    T("Core & Pull","Abs, Back & Glutes",["core","back","glutes"],[]),
  ];
  if (count === 3) return [
    T("Core & Push","Abs & Chest",["core","chest"],["shoulders","arms"]),
    T("Core & Pull","Abs & Back",["core","back"],["arms"]),
    T("Core & Lower","Abs & Glutes",["core","glutes"],["legs"]),
  ];
  if (count === 4) return [
    T("Core & Chest","Abs & Push",["core","chest"],["arms"]),
    T("Core & Back","Abs & Pull",["core","back"],["arms"]),
    T("Core & Glutes","Abs & Lower",["core","glutes"],["legs"]),
    T("Full Core","Complete Midsection",["core"],["shoulders","glutes"]),
  ];
  // 5-7 days core
  const coreDays = [
    T("Core & Chest","Abs & Push",["core","chest"],["arms"]),
    T("Core & Back","Abs & Pull",["core","back"],["arms"]),
    T("Core & Glutes","Abs & Lower",["core","glutes"],["legs"]),
    T("Full Core A","Complete Midsection",["core"],["shoulders"]),
    T("Core & Shoulders","Obliques & Delts",["core","shoulders"],[]),
    T("Full Core B","Core Burnout",["core"],["glutes"]),
    T("Active Recovery","Mobility & Stretch",["core"],[]),
  ];
  return coreDays.slice(0, count);
}

// Assign session templates to the chosen weekday numbers (0=Sun..6=Sat).
function toValidDayIndex(d) {
  // Accept number 0-6, or a day name string like "Monday"
  if (typeof d === 'number' && d >= 0 && d <= 6) return d;
  const asInt = parseInt(d, 10);
  if (!isNaN(asInt) && asInt >= 0 && asInt <= 6) return asInt;
  const nameIdx = DAY_NAMES.indexOf(String(d));
  return nameIdx >= 0 ? nameIdx : null;
}

// ── BASIC-PROGRAM PERIODIZATION (Upper / Lower / Full / Core only) ────────────
// A 90-day / 12-week block. Intensity steps every 2 weeks (6 blocks); exercises
// rotate every 4 weeks (sets A/B/C). Experience level sets the starting block,
// the ceiling, and a frequency lean. Calendar-driven like HFT/GLB — the program
// auto-advances as real weeks pass. Every value is a coach-overridable default.
const BASIC_BLOCKS = [
  { reps:"12-15", sets:"3", rest:"75s",  tag:"Foundation" },
  { reps:"10-12", sets:"3", rest:"90s",  tag:"Add load" },
  { reps:"8-12",  sets:"4", rest:"90s",  tag:"Build volume" },
  { reps:"8-10",  sets:"4", rest:"120s", tag:"Heavier" },
  { reps:"6-8",   sets:"4", rest:"120s", tag:"Strength" },
  { reps:"6-10",  sets:"5", rest:"150s", tag:"Peak" },
];
// Week 1–12 within the current 90-day block; re-baselines (loops) afterward.
function basicProgramWeek(startDate) {
  if (!startDate) return 1;
  const days = Math.max(0, Math.floor((new Date() - new Date(startDate)) / 86400000));
  return (Math.floor(days / 7) % 12) + 1;
}
// Experience level → starting block index + ceiling. Beginners start gentle and
// cap mid-ramp; advanced/pro start already loaded and reach the peak.
function basicLevelRamp(level) {
  if (level === "Beginner") return { start:0, cap:3 };
  if (level === "Advanced") return { start:1, cap:5 };
  if (level === "Pro")      return { start:1, cap:5 };
  return { start:0, cap:5 }; // Intermediate
}
// Which intensity block + 4-week exercise rotation applies to this client right now.
function basicBlockFor(profile) {
  const week = basicProgramWeek(profile && profile.basicStartDate);
  const { start, cap } = basicLevelRamp((profile && profile.fitnessLevel) || "Intermediate");
  const blockIndex = Math.min(start + Math.floor((week - 1) / 2), cap);
  return { week, blockIndex, block: BASIC_BLOCKS[blockIndex], rotation: Math.floor((week - 1) / 4) % 3 };
}
// Apply a block's sets/reps/rest to an exercise, preserving time-holds, "to failure",
// and per-side ("each") rep formats so a plank never becomes "8-10 reps".
function applyBlock(ex, block) {
  if (!block) return ex;
  const r = String(ex.reps || "");
  const reps = /hold|fail|sec|min|\d+\s*s\b/i.test(r) ? ex.reps
             : /each/i.test(r) ? `${block.reps} each`
             : block.reps;
  return { ...ex, sets: block.sets, reps, rest: block.rest };
}

function buildWeek(profile) {
  const raw = (profile.trainingDays && profile.trainingDays.length)
    ? [...profile.trainingDays]
    : DEFAULT_DAYS;
  const days = raw
    .map(toValidDayIndex)
    .filter(d => d !== null)
    .sort((a,b)=>a-b);
  const validDays = days.length ? days : DEFAULT_DAYS;
  const templates = sessionTemplates(profile.focus, validDays.length, profile.goal, profile.gender);
  const target = exercisesForTime(profile.sessionTime);
  const { block, rotation } = basicBlockFor(profile);   // periodize this week
  return validDays.map((dayNum, i) => {
    const t = templates[i % templates.length];
    return dayPlan(DAY_NAMES[dayNum], t.type, t.focusText, t.primary, t.accessory, target, { block, rotation });
  });
}


// ── HIGH FREQUENCY TRAINING — 90-DAY GRADUATED PROGRAM ──────────────────────
// Based on high-frequency bodybuilding methodology (Serge Nubret et al.)
// Phase 1 (Weeks 1–3):  3 days — Foundation
// Phase 2 (Weeks 4–6):  4 days — Building
// Phase 3 (Weeks 7–9):  6 days — Developing (PPL x2)
// Phase 4 (Weeks 10–12): 6 days — Full HFT Protocol

function getHFTPhase(hftStartDate) {
  if (!hftStartDate) return 1;
  const start = new Date(hftStartDate);
  const today = new Date();
  const days = Math.floor((today - start) / (1000 * 60 * 60 * 24));
  if (days < 21)  return 1;
  if (days < 42)  return 2;
  if (days < 63)  return 3;
  if (days < 90)  return 4;
  return 4; // Stay at Phase 4 after day 90
}

function getHFTPhaseInfo(phase) {
  return [
    { num:1, name:"Foundation",   weeks:"Weeks 1–3",   days:3, focus:"3 days per week. Building movement patterns and connective tissue tolerance.", color:"#3d8eff" },
    { num:2, name:"Building",     weeks:"Weeks 4–6",   days:4, focus:"4 days per week. Each muscle group trained twice weekly.", color:"#9b5de5" },
    { num:3, name:"Developing",   weeks:"Weeks 7–9",   days:6, focus:"6 days per week. Push / Pull / Legs twice through.", color:"#e8ff00" },
    { num:4, name:"High Frequency", weeks:"Weeks 10–12", days:6, focus:"Full HFT protocol. 6 days, full body, varying rep targets daily.", color:"#ff3d3d" },
  ][phase - 1];
}

