function buildHFTProgram(profile) {
  const phase = getHFTPhase(profile.hftStartDate);
  const info  = getHFTPhaseInfo(phase);
  const labels = HFT_DAY_LABELS[phase];
  const sessions = ["p1A","p1B","p1C","p2UpperHeavy","p2LowerHeavy","p2UpperVolume","p2LowerVolume",
    "p3PushA","p3PullA","p3LegsA","p3PushB","p3PullB","p3LegsB",
    "p4Heavy","p4Moderate","p4Volume","p4Hypertrophy","p4Density","p4Pump"];

  const sessionKeys = {
    1: ["p1A","p1B","p1C"],
    2: ["p2UpperHeavy","p2LowerHeavy","p2UpperVolume","p2LowerVolume"],
    3: ["p3PushA","p3PullA","p3LegsA","p3PushB","p3PullB","p3LegsB"],
    4: ["p4Heavy","p4Moderate","p4Volume","p4Hypertrophy","p4Density","p4Pump"],
  }[phase];

  const weeklySchedule = sessionKeys.map((key, i) => ({
    day:    labels[i].day,
    type:   labels[i].type,
    focus:  labels[i].focus,
    workout: HFT_EX[key],
  }));

  return {
    hftPhase: phase,
    overview: "90-Day High Frequency Training Program — Phase " + phase + ": " + info.name + " (" + info.weeks + "). " + info.focus,
    weeklySchedule,
    stretching: "full",
    nutrition: macrosFor(profile),
    progressMilestones: [
      { week:1, goal:"Focus on movement quality. Do not chase weight. The frequency will challenge you enough." },
      { week:2, goal:"Begin adding small amounts of weight to compound movements. Keep form perfect." },
      { week:3, goal:"Final week of this phase. Push the last set of each exercise close to failure." },
    ],
  };
}
// ─────────────────────────────────────────────────────────────────────────────



// ── GLUTE & LOWER BODY — 90-DAY GRADUATED PROGRAM ────────────────────────────
// The modern hourglass build: round/lifted glutes, fuller hips, developed
// thighs with inner-thigh work, and a small-looking waist via deep-core (TVA)
// training + proportional contrast. Deliberately avoids heavy loaded oblique
// work (which thickens the waist). Same graduated 4-phase structure as HFT.
//   Phase 1 (Wks 1–3):  3 days — Foundation (movement patterns + glute activation)
//   Phase 2 (Wks 4–6):  4 days — Building (load + volume)
//   Phase 3 (Wks 7–9):  5 days — Developing (heavy compounds + isolation)
//   Phase 4 (Wks 10–12): 5 days — Sculpt & Peak

function getGLBPhase(glbStartDate) {
  if (!glbStartDate) return 1;
  const start = new Date(glbStartDate);
  const today = new Date();
  const days = Math.floor((today - start) / (1000 * 60 * 60 * 24));
  if (days < 21) return 1;
  if (days < 42) return 2;
  if (days < 63) return 3;
  if (days < 90) return 4;
  return 4;
}

function getGLBPhaseInfo(phase) {
  return [
    { num:1, name:"Foundation",    weeks:"Weeks 1–3",   days:3, focus:"3 days per week. Learn the movements, master glute activation and the waist vacuum.", color:"#ff5fa2" },
    { num:2, name:"Building",       weeks:"Weeks 4–6",   days:4, focus:"4 days per week. Add load and volume. Hips & glutes trained twice weekly.", color:"#c95fff" },
    { num:3, name:"Developing",     weeks:"Weeks 7–9",   days:5, focus:"5 days per week. Heavier compounds plus targeted glute, hip and inner-thigh isolation.", color:"#9b5de5" },
    { num:4, name:"Sculpt & Peak",  weeks:"Weeks 10–12", days:5, focus:"5 days per week. Peak intensity — heavy strength plus high-volume burnout & pump.", color:"#ff3d8b" },
  ][phase - 1];
}

