function buildGLBProgram(profile) {
  const phase = getGLBPhase(profile.glbStartDate);
  const info  = getGLBPhaseInfo(phase);
  const labels = GLB_DAY_LABELS[phase];
  const rawUserDays = (profile.trainingDays && profile.trainingDays.length)
    ? [...profile.trainingDays]
    : [1,3,5];
  const userDays = rawUserDays
    .map(toValidDayIndex)
    .filter(d => d !== null)
    .sort((a,b)=>a-b)
    .filter((v,i,a)=>a.indexOf(v)===i); // dedupe

  const sessionKeys = {
    1: ["glb1A","glb1B","glb1C"],
    2: ["glb2Glute","glb2Quad","glb2Ham","glb2Sculpt"],
    3: ["glb3GluteHeavy","glb3Quad","glb3HamGlute","glb3HipSculpt","glb3Burn"],
    4: ["glb4GlutePeak","glb4LegPeak","glb4HamPeak","glb4Sculpt","glb4Burn"],
  }[phase];

  const weeklySchedule = userDays.map((dayNum, i) => {
    const key   = sessionKeys[i % sessionKeys.length];
    const label = labels[i % labels.length];
    return {
      day:     DAY_NAMES[dayNum],
      type:    label.type,
      focus:   label.focus,
      workout: GLB_EX[key],
    };
  });

  return {
    glbPhase: phase,
    overview: "90-Day Glute & Lower Body Program — Phase " + phase + ": " + info.name + " (" + info.weeks + "). " + info.focus,
    weeklySchedule,
    stretching: "lower",
    nutrition: macrosFor(profile),
    progressMilestones: [
      { week:1, goal:"Master glute activation and the stomach vacuum. Feel the glutes working on every rep — that connection is everything." },
      { week:2, goal:"Add light load where the movement feels solid. Keep practicing the vacuum daily." },
      { week:3, goal:"Final foundation week. Push the last set of each glute movement close to failure with perfect form." },
    ],
  };
}
