// ─────────────────────────────────────────────────────────────────────────────

function buildProgram(profile) {
  // Route to At-Home / Active-Aging builder if selected (no gym, low-impact)
  if (profile.focus && profile.focus.includes("Active Aging")) {
    return buildHomeProgram(profile);
  }
  // Route to BodyMorph (No Gym) bodyweight / calisthenics builder if selected
  if (profile.focus && profile.focus.includes("BodyMorph (No Gym)")) {
    return buildCalisthenicsProgram(profile);
  }
  // Route to HFT builder if selected
  if (profile.focus && profile.focus.includes("HFT")) {
    return buildHFTProgram(profile);
  }
  // Route to Glute & Lower Body builder if selected
  if (profile.focus && profile.focus.includes("Booty")) {
    return buildGLBProgram(profile);
  }

  const { stretch } = pickFocusGroups(profile);
  const goalWord = profile.goal.split("(")[0].trim();
  const focusWord = profile.focus.split("(")[0].trim();
  const bb = basicBlockFor(profile);
  const { start, cap } = basicLevelRamp(profile.fitnessLevel || "Intermediate");

  return {
    overview: `A 90-day, 12-week ${focusWord.toLowerCase()} block for your ${goalWord.toLowerCase()} goal. Intensity steps up every 2 weeks, and the exercises rotate every 4 weeks so the same muscles keep adapting. You're in week ${bb.week} — the ${bb.block.tag} phase (${bb.block.sets} sets of ${bb.block.reps}, ${bb.block.rest} rest). Precise angles, controlled tempo, a strong mind-muscle squeeze over heavy momentum.`,
    weeklySchedule: buildWeek(profile),
    stretching: STRETCHES[stretch],
    nutrition: macrosFor(profile),
    basicPeriodized: true,
    currentWeek: bb.week,
    currentBlock: bb.blockIndex + 1,
    // Level-aware roadmap: each 2-week window shows the block THIS client actually
    // reaches (beginners cap early and "hold" at their ceiling instead of being shown
    // Strength/Peak weeks they never hit). Rotation note lands on each new 4-week block.
    progressMilestones: Array.from({ length: 6 }, (_, i) => {
      const idx = Math.min(start + i, cap);
      const held = i > 0 && idx === cap && Math.min(start + (i - 1), cap) === cap;
      const b = BASIC_BLOCKS[idx];
      const fresh = i % 2 === 0 ? " Fresh exercises this block." : "";
      const goal = held
        ? `Weeks ${i * 2 + 1}–${i * 2 + 2} · ${b.tag} (hold): add reps or load within ${b.sets} sets of ${b.reps} and beat last block — strict form.${fresh}`
        : `Weeks ${i * 2 + 1}–${i * 2 + 2} · ${b.tag}: ${b.sets} sets of ${b.reps}, ${b.rest} rest.${fresh}`;
      return { week: i * 2 + 1, goal };
    }),
  };
}

// ── AI-PERSONALIZED PROGRAM ──────────────────────────────────────────────────
// A genuinely individualized weekly program generated by Claude from the client's
// stats, goals, level, focus and schedule — replacing the template builder's
// output when available. Generated ONCE at signup (and again only when the
// structural inputs change), then cached in the profile (profile.aiProgram), so
// it costs a few cents per client, not per app-open. buildProgram() above remains
// the deterministic fallback if no key, generation fails, or for curated focuses.

// Curated, time-phased 90-day focuses keep their periodized templates — the
// progression is the whole point, so we don't let the AI flatten it.
function isAIProgramEligible(profile) {
  // The 4 basic programs (Upper/Lower/Full/Core) are now deterministically
  // PERIODIZED — 90-day blocks, 2-week intensity steps, 4-week exercise rotation.
  // Those guardrails must be guaranteed by code, not left to the AI to honor, so
  // we no longer route any program through the model. The specialty programs were
  // already excluded; templates now own every program. (Kept as a function so the
  // caching/UI call sites still work and AI can be re-enabled later if desired.)
  return false;
}

// Inputs that define the STRUCTURE of a program. Body-weight / metric edits are
// deliberately excluded — those only move nutrition, which we recompute locally —
// so a routine weigh-in never triggers a (paid) regeneration.
function programSignature(profile) {
  if (!profile) return "";
  return [
    profile.focus, profile.goal, profile.gender, profile.fitnessLevel,
    profile.sessionTime, (profile.trainingDays || []).join(","),
    profile.goalWeight, profile.goalBodyFat, profile.age, (profile.deficit || "moderate"),
    (profile.paceMode || "pace"), (profile.deadlineWeeks || ""),
  ].join("|");
}

// What the user actually sees. If a cached AI program exists and still matches the
// current structural inputs, use it (with fresh nutrition so macros stay live);
// otherwise fall back to the deterministic template. Pure + synchronous — never
// calls the API, so it's safe to call from effects and on every profile change.
function resolveProgram(profile) {
  const ai = profile && profile.aiProgram;
  if (ai && profile.aiProgramSig === programSignature(profile) &&
      Array.isArray(ai.weeklySchedule) && ai.weeklySchedule.length) {
    return { ...ai, nutrition: macrosFor(profile) };
  }
  return buildProgram(profile);
}

// Ordered training-day names for the client's chosen days (matches buildWeek).
function orderedTrainingDays(profile) {
  const raw = (profile.trainingDays && profile.trainingDays.length)
    ? [...profile.trainingDays] : DEFAULT_DAYS;
  const days = raw.map(toValidDayIndex).filter(d => d !== null).sort((a,b)=>a-b);
  return (days.length ? days : DEFAULT_DAYS).map(d => DAY_NAMES[d]);
}

// Generate the individualized program with Claude (Sonnet). Async — returns the
// full program object (same shape buildProgram returns) merged with locally
// computed nutrition + stretching. Throws on any failure so callers fall back.
async function generateProgram(profile) {
  if (!USE_PROXY && !ANTHROPIC_KEY) throw new Error("no-key");
  const dayNames = orderedTrainingDays(profile);
  const exCount = exercisesForTime(profile.sessionTime);
  const { stretch } = pickFocusGroups(profile);

  // Realistic time-to-goal drives the program's horizon: the client commits to the
  // full journey, not an arbitrary 4 weeks. Short/no-goal cases stay a 4-week block.
  const tl = goalTimeline(profile, profile.deficit || "moderate");
  const quick = !tl || tl.weeks <= 6;
  const totalWeeks = tl ? tl.weeks : 4;
  const milestoneCount = quick ? 4 : Math.min(6, Math.max(4, Math.round(totalWeeks / 3)));

  const horizonLine = tl
    ? `- REALISTIC TIMELINE TO GOAL: about ${totalWeeks} weeks (${tl.human}), losing/gaining ~${tl.weeklyRate} lb/week to go from ${profile.weight} lbs to a ~${effectiveTargetWeight(profile)} lb target. This is the duration the client is committing to.`
    : `- No specific weight/body-fat goal set — treat this as a focused 4-week block the client can repeat.`;

  const milestoneRule = quick
    ? `- progressMilestones: exactly 4 entries (week 1 through 4), each a concrete week-by-week progression instruction.`
    : `- progressMilestones: exactly ${milestoneCount} checkpoint entries spread across the FULL ${totalWeeks}-week journey (e.g. weeks 1, then roughly evenly up to ${totalWeeks}). The "week" field is the checkpoint week number. Each entry states the realistic physique/performance progress expected by that week AND how training intensifies (load, volume, technique) into the next phase. The final entry is at week ${totalWeeks} — reaching the goal.`;

  const prompt =
`You are an elite strength & physique coach building a precise, individualized training program for a real client — one they will follow for the WHOLE realistic duration it takes to reach their goal, not a throwaway 4-week block. Tailor exercise selection, split, volume and intensity to THIS person. This is not a generic template; make choices a thoughtful human coach would make for them.

CLIENT
- Name: ${profile.name}
- Sex: ${profile.gender}
- Age: ${profile.age}
- Current weight: ${profile.weight} lbs${profile.bodyFat ? `, ~${profile.bodyFat}% body fat` : ""}
- Goal weight: ${profile.goalWeight || "not set"}${profile.goalBodyFat ? `, goal body fat ${profile.goalBodyFat}%` : ""}
- Primary goal: ${profile.goal}
- Training focus: ${profile.focus}
- Experience level: ${profile.fitnessLevel}
- Training days (use EXACTLY these labels, in this order, one workout each): ${dayNames.join(", ")}
- Session length: ${profile.sessionTime} minutes -> about ${exCount} exercises per session
${horizonLine}

REQUIREMENTS
- Produce the weekly split: one workout per training day listed above. The "day" field MUST equal the day name exactly. The client repeats this weekly structure, progressing it over the full timeline.
- Each workout: ${exCount} exercises (give or take one), ordered big compounds first.
- Hit each major muscle group it targets about twice per week across the week; avoid redundant back-to-back overlap.
- Match volume/intensity to the experience level (beginners: simpler movements, moderate volume; advanced: more demanding variations, intensity techniques).
- Every exercise needs realistic sets, a rep range, rest, a tempo (e.g. "3-1-2"), and a short, specific coachCue in second person.
- Tempo format: "ecc-pause-con" digits like "3-1-2". Rest like "90s" or "120s". Reps like "8-12" or "12".
${milestoneRule}
- overview: 2-3 sentences, personal and specific. ${tl ? `State the realistic commitment up front — about ${totalWeeks} weeks (${tl.human}) to reach the goal at a sustainable pace — so the client knows what they're signing up for.` : "Speak to the client's goal and focus."}

Respond with ONLY valid minified JSON, no markdown, no commentary, in exactly this shape:
{"overview":"...","weeklySchedule":[{"day":"Monday","type":"Push","focus":"Chest, Shoulders, Triceps","workout":[{"exercise":"...","sets":"4","reps":"8-12","rest":"90s","tempo":"3-1-2","coachCue":"..."}]}],"progressMilestones":[{"week":1,"goal":"..."},{"week":${quick?4:totalWeeks},"goal":"..."}]}`;

  const res = await anthropicFetch({ model:"claude-sonnet-4-6", max_tokens:4000, messages:[{ role:"user", content:prompt }] });
  if (!res.ok) throw new Error("api-" + res.status);
  const data = await res.json();
  let text = (data.content && data.content[0] && data.content[0].text) || "";
  // Strip any stray code fences and isolate the JSON object.
  text = text.replace(/```json\s*|```/g, "").trim();
  const first = text.indexOf("{"), last = text.lastIndexOf("}");
  if (first === -1 || last === -1) throw new Error("no-json");
  const parsed = JSON.parse(text.slice(first, last + 1));

  // Validate the shape before trusting it.
  if (!Array.isArray(parsed.weeklySchedule) || !parsed.weeklySchedule.length) throw new Error("bad-schedule");
  parsed.weeklySchedule.forEach(d => {
    if (!d || !d.day || !Array.isArray(d.workout) || !d.workout.length) throw new Error("bad-day");
  });
  // Force the days to EXACTLY the client's selection. If the AI returned the wrong
  // number of days, fall back to the template (which always honors the days); if the
  // count is right but labels drifted, overwrite them with the chosen days in order.
  if (parsed.weeklySchedule.length !== dayNames.length) throw new Error("day-count-mismatch");
  parsed.weeklySchedule.forEach((d, i) => { d.day = dayNames[i]; });

  return {
    overview: parsed.overview || buildProgram(profile).overview,
    weeklySchedule: parsed.weeklySchedule,
    stretching: STRETCHES[stretch],
    nutrition: macrosFor(profile),
    progressMilestones: (Array.isArray(parsed.progressMilestones) && parsed.progressMilestones.length)
      ? parsed.progressMilestones
      : buildProgram(profile).progressMilestones,
    timeline: tl,            // realistic time-to-goal the program is built around
    totalWeeks,              // committed program length in weeks
    aiGenerated: true,
  };
}

