              <div style={{ fontSize:24, lineHeight:1.1, flexShrink:0 }}>{b.icon}</div>
              <div>
                <div style={{ fontFamily:"'DM Sans'", fontWeight:700, fontSize:15.5, color:"#f0f0f8", marginBottom:3 }}>{b.title}</div>
