// Per-step guidance shown ONLY in coach mode (the guided intake): what to ask and
// what to steer, so a brand-new coach runs a professional onboarding on day one.
const COACH_TIPS = {
  firstname: "Set the tone: “We're going to build your whole program together right now — takes about five minutes.”",
  address:   "For your client file and in-person sessions. Confirm the spelling back to them.",
  gender:    "Programs and calorie math differ — pick what fits their training profile.",
  goal:      "Dig in here: why this goal, why NOW? Write their reason down — you'll use it when motivation dips.",
  focus:     "Steer them. Beginners do best on Full Body; match the focus to what they said they want to change.",
  days:      "Push for honest, not ambitious — 4 days they'll keep beats 6 they won't. Protect at least one rest day.",
  time:      "Their real window, warm-up included. If they've got 45 minutes at lunch, pick 45.",
  stats:     "Measure now if you can — a scale reading beats a guess. Estimate body fat visually if you have to.",
  goals:     "Set the target together and keep it realistic — you can always raise it. This number drives their calories.",
  activity:  "Their job and daily movement, NOT their workouts — training is counted separately.",
  diet:      "Pick what they'll actually eat, not what's trendy. This drives every meal plan they'll ever generate.",
  cuisines:  "Favorite foods = adherence. Ask what they actually cook at home.",
  shopping:  "Their store shapes the grocery list. Nail the allergies — meal plans will avoid them completely.",
};

function Wizard({ onComplete, onCoachCode, seed, initial, startStep, coachMode, onCancel }) {
  const [step, setStep] = useState(startStep || 0);
  const [showHFTInfo, setShowHFTInfo] = useState(false);
  const [showGLBInfo, setShowGLBInfo] = useState(false);
  // Pre-fill the client's name from a coach invite, when present.
  const seedName = (seed && seed.name) ? String(seed.name).trim() : "";
  const [coachOpen, setCoachOpen] = useState(false);
  const [coachCode, setCoachCode] = useState("");
  const [coachMsg, setCoachMsg] = useState("");
  const [coachBusy, setCoachBusy] = useState(false);
  const submitCoach = async () => {
    setCoachMsg(""); setCoachBusy(true);
    const res = await onCoachCode(coachCode);
    setCoachBusy(false);
    if (!res?.ok) setCoachMsg(res?.error || "Invalid code");
    // On success, the app routes to the dashboard (this screen unmounts).
  };
  // When editing an existing profile (initial), prefill every field so the user
  // can adjust just what they want; derive ft/in from stored height (inches).
  const ini = initial || {};
  const iniH = parseFloat(ini.height);
  const [p, setP] = useState({
    firstName: ini.firstName || seedName.split(" ")[0] || "",
    lastName: ini.lastName || seedName.split(" ").slice(1).join(" ") || "",
    address: ini.address || "",
    name: ini.name || "",
    gender: ini.gender || "",
    goal: ini.goal || "",
    focus: ini.focus || "",
    trainingDays: ini.trainingDays || [],   // start empty — the client consciously picks their days
    sessionTime: ini.sessionTime || 60,
    age: ini.age || "",
    weight: ini.weight || "",
    height: ini.height || "",
    heightFt: iniH ? String(Math.floor(iniH / 12)) : "",
    heightIn: iniH ? String(Math.round(iniH % 12)) : "",
    fitnessLevel: ini.fitnessLevel || "",
    activityLevel: ini.activityLevel || "moderate",
    bodyFat: ini.bodyFat || "",
    goalWeight: ini.goalWeight || "",
    goalBodyFat: ini.goalBodyFat || "",
    deficit: ini.deficit || "moderate",
    // Nutrition preferences — captured at onboarding so the coach walks the client
    // through them once, and every future meal plan starts pre-configured.
    dietPref: ini.dietPref || "",
    carbLevel: ini.carbLevel || "moderate",
    cuisines: ini.cuisines || [],
    store: ini.store || "",
    allergies: ini.allergies || "",
  });
  const set = (k, v) => setP(prev => ({ ...prev, [k]:v }));
  const toggleDay = (d) => setP(prev => ({ ...prev, trainingDays: prev.trainingDays.includes(d) ? prev.trainingDays.filter(x=>x!==d) : [...prev.trainingDays, d] }));

  const canNext = [
    () => p.firstName.trim().length > 0,
    () => p.lastName.trim().length > 0,
    () => p.address.trim().length > 0,
    () => !!p.gender,
    () => !!p.goal,
    () => !!p.focus,
    () => p.trainingDays.length > 0,
    () => !!p.sessionTime,
    () => p.age && p.weight && p.heightFt && p.fitnessLevel,
    () => !!p.goalWeight,   // goal weight required; body-fat fields optional
    () => !!p.activityLevel,
    () => !!p.dietPref,     // diet style required — it drives every meal plan
    () => true,             // cuisines optional
    () => true,             // store + allergies optional
  ];

  const maleFocuses   = ["Upper Body (Chest, Back, Arms, Shoulders)","Lower Body (Legs, Glutes, Calves)","Full Body","Core & Abs","Iconic Physique — HFT (90-Day)","Active Aging — At-Home, Low Impact (No Gym)","BodyMorph (No Gym) — Bodyweight / Calisthenics"];
  const femaleFocuses = ["Lower Body (Hips, Glutes, Legs, Calves)","Upper Body (Arms, Back, Shoulders)","Full Body","Core & Abs","Tight Waist, Booty & Lower Body Blast (90-Day)","Active Aging — At-Home, Low Impact (No Gym)","BodyMorph (No Gym) — Bodyweight / Calisthenics"];
  const focuses = p.gender === "Female" ? femaleFocuses : maleFocuses;

  const Pill = ({ label, active, onClick }) => (
    <button onClick={onClick} style={{ background: active ? "#e8ff00" : "#1a1a26", border:"1px solid " + (active ? "#e8ff00" : "#2a2a3d"), color: active ? "#000" : "#f0f0f8", fontWeight: active ? 600 : 400, borderRadius:8, padding:"10px 13px", cursor:"pointer", fontSize:19.2, fontFamily:"'DM Sans'", textAlign:"left", transition:"all 0.18s", width:"100%" }}>{label}</button>
  );

  const steps = [
    <div key="firstname" style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:18, width:"100%" }}>
      <div style={{ ...S.stepLabel, fontSize:26 }}>FIRST NAME</div>
      <input autoFocus style={{ ...S.input, maxWidth:320, textAlign:"center", fontSize:27 }} placeholder="First Name" value={p.firstName} onChange={e=>set("firstName",e.target.value)} onKeyDown={e=>{ if(e.key==="Enter" && p.firstName.trim()) setStep(1); }} />
      <div style={{ color:"#e8ff00", fontSize:24, letterSpacing:3, textTransform:"uppercase" }}>New Body 4 Life</div>
    </div>,

    <div key="lastname" style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:18, width:"100%" }}>
      <div style={{ ...S.stepLabel, fontSize:26 }}>LAST NAME</div>
      <input autoFocus style={{ ...S.input, maxWidth:320, textAlign:"center", fontSize:27 }} placeholder="Last Name" value={p.lastName} onChange={e=>set("lastName",e.target.value)} onKeyDown={e=>{ if(e.key==="Enter" && p.lastName.trim()) setStep(2); }} />
      <div style={{ color:"#e8ff00", fontSize:24, letterSpacing:3, textTransform:"uppercase" }}>New Body 4 Life</div>
    </div>,

    <div key="address" style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:18, width:"100%" }}>
      <div style={{ ...S.stepLabel, fontSize:26 }}>HOME ADDRESS</div>
      <input autoFocus style={{ ...S.input, maxWidth:360, textAlign:"center", fontSize:19 }} placeholder="Street, City, State ZIP" autoComplete="street-address" value={p.address} onChange={e=>set("address",e.target.value)} onKeyDown={e=>{ if(e.key==="Enter" && p.address.trim()) setStep(3); }} />
      <div style={{ color:"#9898b8", fontSize:14, textAlign:"center", maxWidth:340, lineHeight:1.5 }}>Only your coach sees this — for in-person sessions and your client file.</div>
    </div>,

    <div key="g" style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:9, width:"100%" }}>
      <div style={S.stepLabel}>WHO ARE WE TRAINING?</div>
      <div style={{ display:"flex", gap:12 }}>
        {["Male","Female"].map(g => (
          <button key={g} onClick={() => set("gender",g)} style={{ background: p.gender===g ? "#e8ff00" : "#1a1a26", border:"1px solid " + (p.gender===g ? "#e8ff00" : "#2a2a3d"), color: p.gender===g ? "#000" : "#f0f0f8", fontWeight: p.gender===g ? 600 : 400, borderRadius:12, padding:"14px 25px", cursor:"pointer", display:"flex", flexDirection:"column", alignItems:"center", gap:6, fontSize:20.4, fontFamily:"'DM Sans'", transition:"all 0.18s", minWidth:110 }}>
            <span style={{ fontSize:42 }}>{g==="Male" ? "\u2642" : "\u2640"}</span>
            <span>{g}</span>
          </button>
        ))}
      </div>
    </div>,

    <div key="goal" style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:8, width:"100%" }}>
      <div style={S.stepLabel}>YOUR PRIMARY GOAL</div>
      <div style={{ display:"flex", flexDirection:"column", gap:7, width:"92%", maxWidth:340 }}>
        {["Bulk (Build Muscle Mass)","Cut (Lose Fat, Preserve Muscle)","Reshape (Build Muscle & Lose Fat)","Athletic Performance"].map(g => (
          <Pill key={g} label={g} active={p.goal===g} onClick={() => set("goal",g)} />
        ))}
      </div>
    </div>,

    <div key="focus" style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:8, width:"100%" }}>
      <div style={S.stepLabel}>TRAINING FOCUS</div>
      <div style={{ display:"flex", flexDirection:"column", gap:7, width:"92%", maxWidth:340 }}>
        {focuses.map(fo => {
          const isHFT = fo.includes("HFT");
          const isGLB = fo.includes("Booty");
          const active = p.focus === fo;
          if (isHFT || isGLB) {
            const openInfo = isHFT ? () => setShowHFTInfo(true) : () => setShowGLBInfo(true);
            const startKey = isHFT ? "hftStartDate" : "glbStartDate";
            return (
              <button key={fo} onClick={() => {
                set("focus", fo);
                if (!p[startKey]) set(startKey, ymdLocal());
              }} style={{ position:"relative", width:"100%", background: active ? "#e8ff00" : "#1a1a26", border:"1px solid " + (active ? "#e8ff00" : "#2a2a3d"), color: active ? "#000" : "#f0f0f8", fontWeight: active ? 600 : 400, borderRadius:8, padding:"10px 34px 10px 13px", cursor:"pointer", fontSize:19.2, fontFamily:"'DM Sans'", textAlign:"left", transition:"all 0.18s" }}>
                {fo}
                <span onClick={(e)=>{ e.stopPropagation(); openInfo(); }} title="What is this?" style={{ position:"absolute", top:8, right:8, width:22, height:22, borderRadius:"50%", border:"1.5px solid " + (active ? "#000" : "#e8ff00"), color: active ? "#000" : "#e8ff00", display:"flex", alignItems:"center", justifyContent:"center", fontSize:13, fontWeight:700, fontStyle:"italic", fontFamily:"Georgia, serif", cursor:"pointer", lineHeight:1 }}>i</span>
              </button>
            );
          }
          return (<Pill key={fo} label={fo} active={active} onClick={() => set("focus", fo)} />);
        })}
      </div>
      {p.focus && (p.focus.includes("HFT") || p.focus.includes("Booty")) && (
        <div style={{ background:"rgba(232,255,0,0.07)", border:"1px solid rgba(232,255,0,0.25)", borderRadius:10, padding:"10px 14px", width:"92%", maxWidth:340, fontSize:13, color:"#c8c8e0", lineHeight:1.6 }}>
          <span style={{ color:"#e8ff00", fontWeight:700 }}>90-DAY PROGRAM</span> — Your program automatically advances through 4 phases. Tap the <span style={{ fontStyle:"italic", fontFamily:"Georgia, serif", color:"#e8ff00", fontWeight:700 }}>i</span> icon to see exactly how it works.
        </div>
      )}
    </div>,

    <div key="days" style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:8, width:"100%" }}>
      <div style={S.stepLabel}>WHICH DAYS WILL YOU TRAIN?</div>
      <div style={{ display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:6, width:"92%", maxWidth:340 }}>
        {DAY_NAMES.map((name, idx) => {
          const on = p.trainingDays.includes(idx);
          return (
            <button key={idx} onClick={()=>toggleDay(idx)} style={{ background: on ? "#e8ff00" : "#1a1a26", border:"1px solid " + (on ? "#e8ff00" : "#2a2a3d"), color: on ? "#000" : "#f0f0f8", borderRadius:8, padding:"10px 8px", cursor:"pointer", fontSize:19.2, fontFamily:"'DM Sans'", fontWeight: on?600:400, textAlign:"center" }}>
              {name}
            </button>
          );
        })}
      </div>
      <div style={{ color: p.trainingDays.length ? "#e8ff00" : "#ff7070", fontSize:16.8, fontFamily:"'Oswald', sans-serif", fontWeight:600 }}>
        {p.trainingDays.length ? p.trainingDays.length + " day" + (p.trainingDays.length>1?"s":"") + " per week" : "Pick at least one day"}
      </div>
    </div>,

    <div key="time" style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:8, width:"100%" }}>
      <div style={S.stepLabel}>HOW LONG PER SESSION?</div>
      <div style={{ display:"flex", flexDirection:"column", gap:7, width:"92%", maxWidth:340 }}>
        {[[30,"30 minutes","Quick — 4 exercises"],[45,"45 minutes","Standard — 5 exercises"],[60,"60+ minutes","Full — 6 exercises"]].map(([val,label,sub]) => {
          const on = p.sessionTime===val;
          return (
            <button key={val} onClick={()=>set("sessionTime",val)} style={{ textAlign:"left", background: on ? "#e8ff00" : "#1a1a26", border:"1px solid " + (on ? "#e8ff00" : "#2a2a3d"), color: on ? "#000" : "#f0f0f8", borderRadius:8, padding:"8px 12px", cursor:"pointer", fontFamily:"'DM Sans'" }}>
              <div style={{ fontFamily:"'Bebas Neue'", fontSize:20.4, letterSpacing:1 }}>{label}</div>
              <div style={{ fontSize:19.2, opacity:0.8 }}>{sub}</div>
            </button>
          );
        })}
      </div>
    </div>,

    <div key="stats" style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:8, width:"100%" }}>
      <div style={S.stepLabel}>YOUR STATS</div>
      <div style={{ display:"flex", flexDirection:"column", gap:9, width:"92%", maxWidth:340 }}>
        {[["age","Age","e.g. 28"],["weight","Weight (lbs)","e.g. 175"]].map(([k,label,ph]) => (
          <div key={k}>
            <div style={S.inputLabel}>{label}</div>
            <input style={S.input} placeholder={ph} value={p[k]} onChange={e => set(k,e.target.value)} type="number" inputMode="numeric" />
          </div>
        ))}
        <div>
          <div style={S.inputLabel}>Height</div>
          <div style={{ display:"flex", gap:8 }}>
            <input style={{ ...S.input, flex:1 }} placeholder="Feet" value={p.heightFt} onChange={e => set("heightFt",e.target.value)} type="number" inputMode="numeric" />
            <input style={{ ...S.input, flex:1 }} placeholder="Inches" value={p.heightIn} onChange={e => set("heightIn",e.target.value)} type="number" inputMode="numeric" />
          </div>
        </div>
        <div>
          <div style={S.inputLabel}>Fitness Level</div>
          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:8 }}>
            {["Beginner","Intermediate","Advanced","Pro"].map(l => (
              <button key={l} onClick={() => set("fitnessLevel",l)} style={{ background: p.fitnessLevel===l ? "#e8ff00" : "#1a1a26", border:"1px solid " + (p.fitnessLevel===l ? "#e8ff00" : "#2a2a3d"), color: p.fitnessLevel===l ? "#000" : "#f0f0f8", fontWeight: p.fitnessLevel===l ? 600 : 400, borderRadius:8, padding:"9px 4px", cursor:"pointer", fontSize:20.4, fontFamily:"'DM Sans'", transition:"all 0.18s", textAlign:"center" }}>{l}</button>
            ))}
          </div>
        </div>
      </div>
    </div>,

    <div key="goals" style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:8, width:"100%" }}>
      <div style={S.stepLabel}>YOUR GOAL</div>
      <div style={{ color:"#c8c8e0", fontSize:13, textAlign:"center", maxWidth:330, lineHeight:1.4 }}>Where do you want to be? Your plan is built around this.</div>
      <div style={{ display:"flex", flexDirection:"column", gap:9, width:"92%", maxWidth:340 }}>
        <div>
          <div style={S.inputLabel}>Goal Weight (lbs)</div>
          <input style={S.input} placeholder="e.g. 165" value={p.goalWeight} onChange={e => set("goalWeight",e.target.value)} type="number" inputMode="decimal" />
        </div>
        <div style={{ display:"flex", gap:8 }}>
          <div style={{ flex:1 }}>
            <div style={S.inputLabel}>Current Body Fat %</div>
            <input style={S.input} placeholder="optional" value={p.bodyFat} onChange={e => set("bodyFat",e.target.value)} type="number" inputMode="decimal" />
          </div>
          <div style={{ flex:1 }}>
            <div style={S.inputLabel}>Goal Body Fat %</div>
            <input style={S.input} placeholder="optional" value={p.goalBodyFat} onChange={e => set("goalBodyFat",e.target.value)} type="number" inputMode="decimal" />
          </div>
        </div>
      </div>
    </div>,

    <div key="activity" style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:4, width:"100%" }}>
      <div style={S.stepLabel}>ACTIVITY LEVEL</div>
      <div style={{ color:"#c8c8e0", fontSize:11, textAlign:"center", maxWidth:320, lineHeight:1.3 }}>
        Outside the gym, how active is your typical day?
      </div>
      <div style={{ display:"flex", flexDirection:"column", gap:3, width:"92%", maxWidth:340 }}>
        {ACTIVITY_LEVELS.map(a => {
          const on = p.activityLevel===a.id;
          return (
            <button key={a.id} onClick={()=>set("activityLevel",a.id)} style={{ textAlign:"left", background: on ? "#e8ff00" : "#1a1a26", border:"1px solid " + (on ? "#e8ff00" : "#2a2a3d"), color: on ? "#000" : "#f0f0f8", borderRadius:8, padding:"5px 9px", cursor:"pointer", fontFamily:"'DM Sans'" }}>
              <div style={{ fontWeight:600, fontSize:15 }}>{a.label}</div>
              <div style={{ fontSize:12.5, opacity:0.8 }}>{a.desc}</div>
            </button>
          );
        })}
      </div>
    </div>,

    <div key="diet" style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:6, width:"100%" }}>
      <div style={S.stepLabel}>DIET STYLE</div>
      <div style={{ color:"#c8c8e0", fontSize:11, textAlign:"center", maxWidth:320, lineHeight:1.3 }}>
        How do you like to eat? Your meal plans are built around this.
      </div>
      <div style={{ display:"grid", gridTemplateColumns:"repeat(2, 1fr)", gap:6, width:"92%", maxWidth:340 }}>
        {DIET_STYLES.map(d => {
          const on = p.dietPref===d.id;
          return (
            <button key={d.id} onClick={()=>set("dietPref",d.id)} style={{ textAlign:"left", background: on ? "#e8ff00" : "#1a1a26", border:"1px solid " + (on ? "#e8ff00" : "#2a2a3d"), color: on ? "#000" : "#f0f0f8", borderRadius:8, padding:"8px 10px", cursor:"pointer", fontFamily:"'DM Sans'" }}>
              <div style={{ fontWeight:600, fontSize:15 }}>{d.emoji} {d.label}</div>
              <div style={{ fontSize:11.5, opacity:0.8, lineHeight:1.25, marginTop:2 }}>{d.tagline}</div>
            </button>
          );
        })}
      </div>
      <div style={{ display:"flex", gap:6, width:"92%", maxWidth:340, marginTop:4 }}>
        {[["low","Low carb"],["moderate","Moderate"],["high","High carb"]].map(([v,label])=>{
          const on = p.carbLevel===v;
          return <button key={v} onClick={()=>set("carbLevel",v)} style={{ flex:1, background: on?"#e8ff00":"#1a1a26", border:`1px solid ${on?"#e8ff00":"#2a2a3d"}`, color: on?"#000":"#c8c8e0", borderRadius:8, padding:"8px 4px", cursor:"pointer", fontSize:13, fontWeight: on?700:500, fontFamily:"'DM Sans'" }}>{label}</button>;
        })}
      </div>
    </div>,

    <div key="cuisines" style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:6, width:"100%" }}>
      <div style={S.stepLabel}>FAVORITE CUISINES</div>
      <div style={{ color:"#c8c8e0", fontSize:11, textAlign:"center", maxWidth:320, lineHeight:1.3 }}>
        Optional — pick any you love and we'll mix them into your meals.
      </div>
      <div style={{ display:"grid", gridTemplateColumns:"repeat(3, 1fr)", gap:6, width:"92%", maxWidth:340 }}>
        {CUISINE_OPTIONS.map(c => {
          const on = p.cuisines.includes(c);
          return <button key={c} onClick={()=>set("cuisines", on ? p.cuisines.filter(x=>x!==c) : [...p.cuisines, c])} style={{ background: on?"rgba(232,255,0,0.15)":"#1a1a26", border:`1px solid ${on?"#e8ff00":"#2a2a3d"}`, color: on?"#e8ff00":"#c8c8e0", borderRadius:8, padding:"9px 4px", cursor:"pointer", fontSize:12.5, fontFamily:"'DM Sans'", fontWeight:600, textAlign:"center", lineHeight:1.2 }}>{on?"✓ ":""}{c}</button>;
        })}
      </div>
    </div>,

    <div key="shopping" style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:6, width:"100%" }}>
      <div style={S.stepLabel}>SHOPPING &amp; ALLERGIES</div>
      <div style={{ color:"#c8c8e0", fontSize:11, textAlign:"center", maxWidth:320, lineHeight:1.3 }}>
        Where do you usually shop? We'll stick to staples they stock and favor their store brands.
      </div>
      <div style={{ display:"grid", gridTemplateColumns:"repeat(3, 1fr)", gap:6, width:"92%", maxWidth:340 }}>
        {Object.keys(STORE_BRANDS).map(s => {
          const on = p.store === s;
          return <button key={s} onClick={()=>set("store", on ? "" : s)} style={{ background: on?"rgba(61,220,132,0.15)":"#1a1a26", border:`1px solid ${on?"#3ddc84":"#2a2a3d"}`, color: on?"#3ddc84":"#c8c8e0", borderRadius:8, padding:"9px 4px", cursor:"pointer", fontSize:12.5, fontFamily:"'DM Sans'", fontWeight:600, textAlign:"center", lineHeight:1.2 }}>{on?"✓ ":""}{s}</button>;
        })}
      </div>
      <div style={{ width:"92%", maxWidth:340, marginTop:4 }}>
        <input style={{ ...S.input, width:"100%", boxSizing:"border-box", fontSize:14 }} placeholder="Not listed? Type your local store (e.g. United Supermarkets)" value={STORE_BRANDS[p.store] ? "" : p.store} onChange={e=>set("store", e.target.value)} />
      </div>
      <div style={{ width:"92%", maxWidth:340, marginTop:6 }}>
        <div style={{ color:"#c8c8e0", fontSize:11, marginBottom:4 }}>Food allergies? (optional — we'll avoid them completely)</div>
        <input style={{ ...S.input, width:"100%", boxSizing:"border-box", fontSize:15 }} placeholder="e.g. peanuts, shellfish, dairy" value={p.allergies} onChange={e=>set("allergies",e.target.value)} />
      </div>
    </div>,
  ];

  const ok = canNext[step] && canNext[step]();

  return (
    <div style={{ ...S.center }}>
      <style>{GLOBAL_CSS}</style>
      <Watermark />
      {showHFTInfo && <HFTInfo onClose={()=>setShowHFTInfo(false)} />}
      {showGLBInfo && <GLBInfo onClose={()=>setShowGLBInfo(false)} />}
      {coachMode ? (
        <div style={{ width:"92%", maxWidth:480, textAlign:"center", position:"relative" }}>
          <div style={{ fontFamily:"'Bebas Neue'", fontSize:26, letterSpacing:2, color:"#e8ff00" }}>GUIDED CLIENT INTAKE</div>
          <div style={{ color:"#9898b8", fontSize:12.5, marginTop:2 }}>Ask the questions out loud — fill it in together{p.firstName ? ` · ${p.firstName.trim()}` : ""}</div>
          {onCancel && (
            <button onClick={onCancel} aria-label="Exit intake" style={{ position:"absolute", right:0, top:-4, background:"transparent", border:"none", color:"#8a8aa4", fontSize:26, lineHeight:1, cursor:"pointer" }}>✕</button>
          )}
        </div>
      ) : (
        <Logo small />
      )}
      <div style={{ display:"flex", gap:5, alignItems:"center" }}>
        {STEPS.map((_,i) => (<div key={i} style={{ height:6, borderRadius:3, transition:"all 0.3s", width: i===step ? 18 : 6, background: i<=step ? "#e8ff00" : "#2a2a3d" }} />))}
      </div>
      <div className="fade-in" key={step} style={{ width:"100%", maxWidth:480, display:"flex", justifyContent:"center" }}>{steps[step]}</div>
      {coachMode && COACH_TIPS[STEPS[step]] && (
        <div style={{ width:"92%", maxWidth:400, background:"rgba(232,255,0,0.06)", border:"1px solid rgba(232,255,0,0.3)", borderRadius:10, padding:"9px 12px", fontSize:12.5, color:"#d2d2ec", lineHeight:1.5 }}>
          <span style={{ background:"#e8ff00", color:"#000", fontSize:10, fontWeight:700, letterSpacing:1, padding:"1px 6px", borderRadius:3, marginRight:7, verticalAlign:"middle" }}>COACH</span>
          {COACH_TIPS[STEPS[step]]}
        </div>
      )}
      <div style={{ display:"flex", gap:7, width:"92%", maxWidth:340 }}>
        {step > 0 && (<button onClick={() => setStep(s=>s-1)} style={{ ...S.btnSec, flex:"0 0 25%", padding:"10px 4px" }}>Back</button>)}
        {step < STEPS.length-1 ? (
          <button onClick={() => ok && setStep(s=>s+1)} disabled={!ok} style={{ ...S.btnPri, flex:1, opacity:ok?1:0.4, cursor:ok?"pointer":"not-allowed", padding:"10px 8px" }}>Continue</button>
        ) : (
          <button onClick={() => { if(!ok) return; const totalIn = (parseInt(p.heightFt)||0)*12 + (parseInt(p.heightIn)||0); onComplete({ ...p, firstName: p.firstName.trim(), lastName: p.lastName.trim(), name: p.firstName.trim(), height: String(totalIn) }); }} disabled={!ok} style={{ ...S.btnPri, flex:"0 0 73%", opacity:ok?1:0.4, cursor:ok?"pointer":"not-allowed", background:"#e8ff00", color:"#000", padding:"10px 6px", fontSize:15.6 }}>{coachMode ? "FINISH INTAKE" : "BUILD MY PROGRAM"}</button>
        )}
      </div>

      {/* Coaches don't onboard as clients — they redeem an access code here. */}
      {step === 0 && onCoachCode && (
        <div style={{ width:"92%", maxWidth:340, marginTop:4, textAlign:"center" }}>
          {!coachOpen ? (
            <button onClick={()=>setCoachOpen(true)} style={{ background:"transparent", border:"none", color:"#9898b8", fontSize:13, cursor:"pointer", textDecoration:"underline" }}>
              I'm a coach — enter access code
            </button>
          ) : (
            <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
              <div style={{ display:"flex", gap:7 }}>
                <input value={coachCode} onChange={e=>setCoachCode(e.target.value)} placeholder="Coach access code" style={{ ...S.input, flex:1 }} />
                <button onClick={submitCoach} disabled={coachBusy || !coachCode.trim()} style={{ ...S.btnPri, padding:"10px 16px", opacity:(coachBusy||!coachCode.trim())?0.5:1 }}>{coachBusy ? "…" : "Go"}</button>
              </div>
              {coachMsg && <div style={{ color:C.red, fontSize:12.5 }}>{coachMsg}</div>}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

// ── LOADING ───────────────────────────────────────────────────────────────────
// YOUR PLAN & TIMELINE — shown after signup for any goal with a weight/body-fat
// target. The whole point: the client sees the REALISTIC timeline they're
// committing to up front (weeks/months + a target date), not a vague 4 weeks.
// Fat-loss goals also pick a pace (mild/moderate/aggressive), each with its own
// honest timeline; the choice persists and drives the program's horizon.
function FatLossResults({ profile, onContinue, onEdit }) {
  const accent = profile.gender === "Female" ? APP_PINK : "#e8ff00";
  const mode = (goalTimeline({ ...profile, paceMode: "pace" }, "moderate") || {}).mode;   // "loss" | "gain" | undefined
  const isLoss = mode === "loss";
  const isGain = mode === "gain";
  const [deficit, setDeficit] = useState(profile.deficit || "moderate");
  // TWO DIALS, one plan: pick a PACE (timeline is computed) or pick a DEADLINE
  // ("wedding in 90 days" — required pace/calories are computed, safety-capped).
  const [planBy, setPlanBy] = useState(profile.paceMode === "deadline" ? "deadline" : "pace");
  const [dlWeeks, setDlWeeks] = useState(parseFloat(profile.deadlineWeeks) || 13);
  const DEADLINES = [
    { wks: 8,  label: "60 days" },
    { wks: 13, label: "90 days" },
    { wks: 16, label: "16 weeks" },
    { wks: 20, label: "~4½ months" },
    { wks: 26, label: "6 months" },
  ];
  const pv = { ...profile, paceMode: planBy, deadlineWeeks: planBy === "deadline" ? dlWeeks : null };
  const t = calorieTargets(pv, deficit);
  const tl = goalTimeline(pv, deficit);
  const m = macrosFor(pv, profile.dietPref);
  const targetW = effectiveTargetWeight(profile);
  const goalLabel = `${targetW ? `~${targetW} lbs` : ""}${profile.goalBodyFat ? `${targetW ? " · " : ""}${profile.goalBodyFat}% body fat` : ""}`;

  const macroCells = isLoss
    ? [["PROTEIN", t.protein, "#3d8eff"],["CARBS", t.carbs, "#9b5de5"],["FATS", t.fats, "#3ddc84"]]
    : [["PROTEIN", parseInt(m.protein), "#3d8eff"],["CARBS", parseInt(m.carbs), "#9b5de5"],["FATS", parseInt(m.fats), "#3ddc84"]];
  const dailyCals = isLoss ? t.target : m.cals;

  return (
    <div style={{ minHeight:"100vh", background:"transparent", paddingBottom:40, position:"relative" }}>
      <style>{GLOBAL_CSS}</style>
      <WatermarkPlain />
      {onEdit && (
        <div style={{ padding:"14px 20px 0" }}>
          <button onClick={onEdit} style={{ background:"transparent", border:"1px solid #2a2a3d", borderRadius:8, color:"#c8c8e0", padding:"7px 12px", cursor:"pointer", fontSize:13 }}>&#8249; Edit my goal</button>
        </div>
      )}
      <div style={{ padding:"24px 20px 8px", textAlign:"center" }}>
        <div style={{ fontFamily:"'Bebas Neue'", fontSize:30, letterSpacing:1, color:accent }}>YOUR PLAN &amp; TIMELINE</div>
        <div style={{ color:"#c8c8e0", fontSize:13.5, lineHeight:1.6, marginTop:6, maxWidth:360, marginLeft:"auto", marginRight:"auto" }}>
          {tl ? "Here's how long it realistically takes to reach your goal — and what to commit to."
              : "Your weekly program is ready. Stay consistent and track your progress."}
        </div>
      </div>

      <div style={{ padding:"8px 20px 0" }}>
        {/* Commitment / timeline headline */}
        {tl && (
          <div style={{ background:"#1a1a26", border:"2px solid "+accent, borderRadius:16, padding:"20px", textAlign:"center", marginBottom:16 }}>
            <div style={{ color:"#c8c8e0", fontSize:12.5, letterSpacing:1 }}>REALISTIC TIME TO YOUR GOAL</div>
            <div style={{ fontFamily:"'Oswald', sans-serif", fontWeight:700, fontSize:44, color:accent, lineHeight:1.1, marginTop:2 }}>{tl.human}</div>
            <div style={{ color:"#f0f0f8", fontSize:13.5, marginTop:4 }}>
              to reach {goalLabel || "your goal"} &middot; target <b>{tl.etaDate}</b>
            </div>
            <div style={{ color:"#9898b8", fontSize:12, marginTop:6 }}>
              about {tl.weeks} weeks of consistency at ~{tl.weeklyRate} lb {isGain ? "of lean gain" : "lost"} per week
            </div>
            {!isGain && (
              <div style={{ marginTop:10, paddingTop:10, borderTop:"1px solid #2a2a3d", color:"#3ddc84", fontSize:12.5 }}>
                🚶 Daily steps target <b>{stepTargetFor(profile).toLocaleString()}</b> — walking is part of the plan. Beat it consistently and you'll reach your goal sooner.
              </div>
            )}
          </div>
        )}

        {/* Fat-loss: TWO ways to plan — pick a pace (timeline computed) or pick a
            deadline (pace/calories computed, safety-capped). */}
        {isLoss && (
          <>
            <div style={{ display:"flex", gap:8, marginBottom:12 }}>
              {[["pace","PICK A PACE"],["deadline","PICK A DEADLINE"]].map(([id,label]) => (
                <button key={id} onClick={()=>setPlanBy(id)} style={{ flex:1, background: planBy===id ? accent : "#1a1a26", color: planBy===id ? "#000" : "#c8c8e0", border:"1px solid " + (planBy===id ? accent : "#2a2a3d"), borderRadius:10, padding:"11px 6px", cursor:"pointer", fontWeight:700, fontSize:13, letterSpacing:0.5, fontFamily:"'DM Sans'" }}>{label}</button>
              ))}
            </div>

            {planBy === "pace" && (
              <div style={{ display:"flex", flexDirection:"column", gap:10, marginBottom:18 }}>
                {DEFICIT_LEVELS.map(d => {
                  const on = deficit===d.id;
                  const dtl = goalTimeline({ ...profile, paceMode:"pace" }, d.id);
                  return (
                    <button key={d.id} onClick={()=>setDeficit(d.id)} style={{ textAlign:"left", background: on ? accent : "#1a1a26", border:"1px solid " + (on ? accent : "#2a2a3d"), color: on ? "#000" : "#f0f0f8", borderRadius:12, padding:"13px 16px", cursor:"pointer", fontFamily:"'DM Sans'" }}>
                      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"baseline", gap:8 }}>
                        <span style={{ fontWeight:700, fontSize:15 }}>{d.label}</span>
                        {dtl && <span style={{ fontWeight:700, fontSize:14 }}>{dtl.human}</span>}
                      </div>
                      <div style={{ fontSize:12, opacity:0.85, marginTop:2 }}>
                        {d.desc}{dtl ? ` · target ${dtl.etaDate}` : ""}
                      </div>
                    </button>
                  );
                })}
              </div>
            )}

            {planBy === "deadline" && (
              <div style={{ marginBottom:18 }}>
                <div style={{ color:"#c8c8e0", fontSize:12.5, lineHeight:1.6, marginBottom:10 }}>
                  Got a wedding, reunion, or beach trip? Pick the window and we'll set the pace and nutrition to get you there — capped at a safe rate.
                </div>
                <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
                  {DEADLINES.map(dl => {
                    const on = dlWeeks === dl.wks;
                    const dtl = goalTimeline({ ...profile, paceMode:"deadline", deadlineWeeks: dl.wks });
                    const feasible = dtl?.deadline?.feasible;
                    const eta = new Date(Date.now() + dl.wks * 7 * 86400000);
                    return (
                      <button key={dl.wks} onClick={()=>setDlWeeks(dl.wks)} style={{ textAlign:"left", background: on ? accent : "#1a1a26", border:"1px solid " + (on ? accent : "#2a2a3d"), color: on ? "#000" : "#f0f0f8", borderRadius:12, padding:"13px 16px", cursor:"pointer", fontFamily:"'DM Sans'" }}>
                        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"baseline", gap:8 }}>
                          <span style={{ fontWeight:700, fontSize:15 }}>{dl.label}</span>
                          <span style={{ fontWeight:700, fontSize:14 }}>
                            {dtl ? (feasible ? `~${dtl.weeklyRate} lb/wk` : `${dtl.deadline.lbsByDeadline} of ${dtl.lbs} lb`) : ""}
                          </span>
                        </div>
                        <div style={{ fontSize:12, opacity:0.85, marginTop:2 }}>
                          by {fmtGoalDate(eta)}{dtl && !feasible ? " · full goal needs longer — this is the safe max" : ""}
                        </div>
                      </button>
                    );
                  })}
                </div>
                {tl && tl.deadline && !tl.deadline.feasible && (
                  <div style={{ marginTop:10, background:"rgba(255,157,92,0.08)", border:"1px solid rgba(255,157,92,0.35)", borderRadius:10, padding:"11px 13px", color:"#ff9d5c", fontSize:12.5, lineHeight:1.6 }}>
                    Straight talk: your goal needs ~{tl.deadline.requiredRate} lb/week — above the safe limit. At the maximum safe pace you'll be down about <b>{tl.deadline.lbsByDeadline} lb</b> by your date, and hit the full goal around <b>{tl.etaDate}</b>.
                  </div>
                )}
              </div>
            )}
          </>
        )}

        {isGain && (
          <div style={{ color:"#c8c8e0", fontSize:12.5, lineHeight:1.6, textAlign:"center", marginBottom:16 }}>
            Muscle is built slowly. Eat at a slight surplus, train hard, and expect steady lean gains — there's no shortcut, and that's why the timeline is what it is.
          </div>
        )}

        {/* Daily target + macros */}
        <div style={{ background:"#1a1a26", border:"1px solid "+accent, borderRadius:16, padding:"18px", textAlign:"center", marginBottom:14 }}>
          <div style={{ color:"#c8c8e0", fontSize:12.5, letterSpacing:1 }}>DAILY CALORIE TARGET</div>
          <div style={{ fontFamily:"'Oswald', sans-serif", fontWeight:700, fontSize:46, color:accent, lineHeight:1.1 }}>{dailyCals}</div>
          <div style={{ color:"#c8c8e0", fontSize:12.5 }}>calories / day</div>
          {isLoss && (
            <div style={{ display:"flex", justifyContent:"center", gap:16, marginTop:10, color:"#9898b8", fontSize:12 }}>
              <span>Maintenance: {t.tdee}</span><span>BMR: {t.bmr}</span>
            </div>
          )}
        </div>

        <div style={{ display:"flex", gap:10, marginBottom:18 }}>
          {macroCells.map(([k,v,col]) => (
            <div key={k} style={{ flex:1, background:"#1a1a26", border:"1px solid #2a2a3d", borderRadius:12, padding:"14px 6px", textAlign:"center" }}>
              <div style={{ color:col, fontFamily:"'Oswald', sans-serif", fontWeight:700, fontSize:22 }}>{v}g</div>
              <div style={{ color:"#c8c8e0", fontSize:11, letterSpacing:0.5, marginTop:2 }}>{k}</div>
            </div>
          ))}
        </div>

        <div style={{ color:"#9898b8", fontSize:11.5, lineHeight:1.6, textAlign:"center", marginBottom:18 }}>
          Science-based estimates (Mifflin-St Jeor). Real results vary with consistency, sleep and adherence &mdash; we'll adjust from your weekly progress. Guidance, not medical advice.
        </div>

        <button onClick={()=>onContinue(deficit, planBy, dlWeeks)} style={{ width:"100%", background:accent, color:"#000", border:"none", borderRadius:14, padding:"17px", cursor:"pointer", fontFamily:"'Bebas Neue'", letterSpacing:2, fontSize:22 }}>
          {tl ? "I'M COMMITTED — START" : "GO TO MY PROGRAM"}
        </button>
      </div>
    </div>
  );
}

function Loading({ name }) {
  const msgs = ["Analyzing your profile...","Selecting your best exercises...","Setting your training angles...","Building your nutrition plan...","Finalizing your program..."];
  const [i, setI] = useState(0);
  useEffect(() => { const t = setInterval(() => setI(x => (x+1) % msgs.length), 1700); return () => clearInterval(t); }, []);
  return (
    <div style={S.center}>
      <style>{GLOBAL_CSS}</style>
      <WatermarkPlain />
      <Logo />
      <div style={{ width:60, height:60, border:"3px solid #2a2a3d", borderTop:"3px solid #e8ff00", borderRadius:"50%", animation:"spin 1s linear infinite" }} />
      <div style={{ color:"#e8ff00", fontFamily:"'Bebas Neue'", fontSize:20, letterSpacing:2 }}>{msgs[i]}</div>
      <div style={{ color:"#c8c8e0", fontSize:14 }}>{name ? name + ", building your 5-day plan" : "Building your 5-day plan"}</div>
    </div>
  );
}

// ── HOME ──────────────────────────────────────────────────────────────────────
// Clean landing: greeting, program summary, then the Mon-Fri week to pick from.
function ChangeProgram({ profile, onSave, onBack }) {
  const maleFocuses   = ["Upper Body (Chest, Back, Arms, Shoulders)","Lower Body (Legs, Glutes, Calves)","Full Body","Core & Abs","Iconic Physique — HFT (90-Day)","Active Aging — At-Home, Low Impact (No Gym)","BodyMorph (No Gym) — Bodyweight / Calisthenics"];
  const femaleFocuses = ["Lower Body (Hips, Glutes, Legs, Calves)","Upper Body (Arms, Back, Shoulders)","Full Body","Core & Abs","Tight Waist, Booty & Lower Body Blast (90-Day)","Active Aging — At-Home, Low Impact (No Gym)","BodyMorph (No Gym) — Bodyweight / Calisthenics"];
  const focuses = profile.gender === "Female" ? femaleFocuses : maleFocuses;
  const [focus, setFocus] = useState(profile.focus || "Full Body");
  const [showHFTInfo, setShowHFTInfo] = useState(false);
  const [showGLBInfo, setShowGLBInfo] = useState(false);
  const changed = focus !== profile.focus;

  const descFor = (f) => {
    if (f.includes("HFT")) return "A 90-day program that gradually builds from 3 to 6 training days per week. Advanced — works your way up to an iconic, complete physique.";
    if (f.includes("Booty")) return "A 90-day program for the hourglass build — a tighter waist, round lifted booty, fuller hips and toned thighs. Builds up gradually over 4 phases.";
    if (f.includes("Full Body")) return "Every session trains your whole body. Great for 2-4 days per week and balanced development.";
    if (f.includes("Upper Body")) return "Emphasis on chest, back, shoulders and arms. Builds upper-body strength and size.";
    if (f.includes("Lower Body")) return "Emphasis on legs, glutes and calves. Builds lower-body strength and shape.";
    if (f.includes("Core")) return "Emphasis on abs and core stability, with supporting compound movements.";
    return "";
  };

  return (
    <div style={{ minHeight:"100vh", background:"transparent", paddingBottom:40, position:"relative" }}>
      <style>{GLOBAL_CSS}</style>
      <Watermark />
      {showHFTInfo && <HFTInfo onClose={()=>setShowHFTInfo(false)} />}
      {showGLBInfo && <GLBInfo onClose={()=>setShowGLBInfo(false)} />}
      <div style={{ display:"flex", alignItems:"center", gap:12, padding:"16px 20px 8px" }}>
        <button onClick={onBack} style={{ background:"transparent", border:"1px solid #2a2a3d", borderRadius:8, color:"#c8c8e0", padding:"7px 12px", cursor:"pointer", fontSize:14 }}>&#8249; Back</button>
        <div style={{ fontFamily:"'Bebas Neue'", fontSize:22, letterSpacing:1 }}>CHANGE PROGRAM</div>
      </div>

      <div style={{ padding:"12px 20px 0" }}>
        <div style={{ color:"#c8c8e0", fontSize:13.5, textAlign:"center", lineHeight:1.6, marginBottom:16 }}>
          Pick a new training focus. Your workout history, body stats, and progress are all kept — only your program changes.
        </div>

        <div style={{ display:"flex", flexDirection:"column", gap:8, width:"100%", maxWidth:360, margin:"0 auto" }}>
          {focuses.map(fo => {
            const on = focus === fo;
            const isHFT = fo.includes("HFT");
            const isGLB = fo.includes("Booty");
            const hasInfo = isHFT || isGLB;
            return (
              <button key={fo} onClick={()=>setFocus(fo)} style={{ position:"relative", width:"100%", textAlign:"left", background: on ? "rgba(232,255,0,0.1)" : "#1a1a26", border:"2px solid " + (on ? "#e8ff00" : "#2a2a3d"), borderRadius:10, padding:"12px 14px", cursor:"pointer", transition:"all 0.15s" }}>
                <div style={{ fontFamily:"'DM Sans'", fontSize:16, fontWeight:600, color: on ? "#e8ff00" : "#f0f0f8", paddingRight: hasInfo ? 30 : 0 }}>{fo}</div>
                <div style={{ fontSize:12, color:"#9898b8", marginTop:3, lineHeight:1.5 }}>{descFor(fo)}</div>
                {hasInfo && (
                  <span onClick={(e)=>{ e.stopPropagation(); (isHFT ? setShowHFTInfo : setShowGLBInfo)(true); }} title="What is this?" style={{ position:"absolute", top:8, right:8, width:22, height:22, borderRadius:"50%", border:"1.5px solid #e8ff00", color:"#e8ff00", display:"flex", alignItems:"center", justifyContent:"center", fontSize:13, fontWeight:700, fontStyle:"italic", fontFamily:"Georgia, serif", cursor:"pointer", lineHeight:1 }}>i</span>
                )}
              </button>
            );
          })}
        </div>

        {focus.includes("HFT") && !profile.focus.includes("HFT") && (
          <div style={{ background:"rgba(232,255,0,0.07)", border:"1px solid rgba(232,255,0,0.25)", borderRadius:10, padding:"10px 14px", marginTop:14, fontSize:12.5, color:"#c8c8e0", lineHeight:1.6, maxWidth:360, marginLeft:"auto", marginRight:"auto" }}>
            <span style={{ color:"#e8ff00", fontWeight:700 }}>NEW 90-DAY PROGRAM</span> — Switching to Iconic Physique — HFT will start a fresh 90-day cycle from today.
          </div>
        )}
        {focus.includes("Booty") && !profile.focus.includes("Booty") && (
          <div style={{ background:"rgba(232,255,0,0.07)", border:"1px solid rgba(232,255,0,0.25)", borderRadius:10, padding:"10px 14px", marginTop:14, fontSize:12.5, color:"#c8c8e0", lineHeight:1.6, maxWidth:360, marginLeft:"auto", marginRight:"auto" }}>
            <span style={{ color:"#e8ff00", fontWeight:700 }}>NEW 90-DAY PROGRAM</span> — Switching to the Tight Waist, Booty &amp; Lower Body Blast will start a fresh 90-day cycle from today.
          </div>
        )}

        <button onClick={()=> changed && onSave(focus)} disabled={!changed} style={{ width:"100%", maxWidth:360, margin:"18px auto 0", display:"block", background: changed ? "#e8ff00" : "#2a2a3d", color: changed ? "#000" : "#9898b8", border:"none", borderRadius:12, padding:"16px", cursor: changed?"pointer":"not-allowed", fontFamily:"'Bebas Neue'", letterSpacing:2, fontSize:20 }}>
          {changed ? "SWITCH TO THIS PROGRAM" : "THIS IS YOUR CURRENT PROGRAM"}
        </button>
      </div>
    </div>
  );
}

function EditDays({ profile, onSave, onBack }) {
  const [days, setDays] = useState((profile.trainingDays && profile.trainingDays.length) ? [...profile.trainingDays] : [...DEFAULT_DAYS]);
  const toggle = (d) => setDays(prev => prev.includes(d) ? prev.filter(x=>x!==d) : [...prev, d]);
  const changed = JSON.stringify([...days].sort()) !== JSON.stringify([...(profile.trainingDays||DEFAULT_DAYS)].sort());

  return (
    <div style={{ minHeight:"100vh", background:"transparent", paddingBottom:40, position:"relative" }}>
      <style>{GLOBAL_CSS}</style>
      <WatermarkPlain />
      <div style={{ display:"flex", alignItems:"center", gap:12, padding:"16px 20px 8px" }}>
        <button onClick={onBack} style={{ background:"transparent", border:"1px solid #2a2a3d", borderRadius:8, color:"#c8c8e0", padding:"7px 12px", cursor:"pointer", fontSize:14 }}>&#8249; Home</button>
        <div style={{ fontFamily:"'Bebas Neue'", fontSize:22, letterSpacing:1 }}>EDIT TRAINING DAYS</div>
      </div>

      <div style={{ padding:"12px 20px 0" }}>
        <div style={{ color:"#c8c8e0", fontSize:13.5, textAlign:"center", lineHeight:1.6, marginBottom:16 }}>
          Tap the days you want to work out. Your program adapts to how many days you pick.
        </div>
        <div style={{ display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:6, width:"80%", maxWidth:272, margin:"0 auto" }}>
          {DAY_NAMES.map((name, idx) => {
            const on = days.includes(idx);
            return (
              <button key={idx} onClick={()=>toggle(idx)} style={{ background: on ? "#e8ff00" : "#1a1a26", border:"1px solid " + (on ? "#e8ff00" : "#2a2a3d"), color: on ? "#000" : "#f0f0f8", borderRadius:8, padding:"9px 6px", cursor:"pointer", fontSize:13, fontFamily:"'DM Sans'", fontWeight: on?600:400, textAlign:"center" }}>
                {name}
              </button>
            );
          })}
        </div>
        <div style={{ color: days.length ? "#e8ff00" : "#ff7070", fontSize:13, fontFamily:"'Oswald', sans-serif", fontWeight:600, textAlign:"center", margin:"14px 0" }}>
          {days.length ? days.length + " day" + (days.length>1?"s":"") + " per week" : "Pick at least one day"}
        </div>

        <button onClick={()=> days.length && onSave([...days].sort((a,b)=>a-b))} disabled={!days.length || !changed} style={{ width:"100%", background: (days.length && changed) ? "#e8ff00" : "#2a2a3d", color: (days.length && changed) ? "#000" : "#9898b8", border:"none", borderRadius:12, padding:"16px", cursor: (days.length && changed)?"pointer":"not-allowed", fontFamily:"'Bebas Neue'", letterSpacing:2, fontSize:20 }}>
          SAVE CHANGES
        </button>
      </div>
    </div>
  );
}

function EditTime({ profile, onSave, onBack }) {
  const current = profile.sessionTime || 60;
  const [time, setTime] = useState(current);
  const changed = time !== current;
  const opts = [[30,"30 minutes","Quick — 4 exercises"],[45,"45 minutes","Standard — 5 exercises"],[60,"60+ minutes","Full — 6 exercises"]];

  return (
    <div style={{ minHeight:"100vh", background:"transparent", paddingBottom:40, position:"relative" }}>
      <style>{GLOBAL_CSS}</style>
      <WatermarkPlain />
      <div style={{ display:"flex", alignItems:"center", gap:12, padding:"16px 20px 8px" }}>
        <button onClick={onBack} style={{ background:"transparent", border:"1px solid #2a2a3d", borderRadius:8, color:"#c8c8e0", padding:"7px 12px", cursor:"pointer", fontSize:14 }}>&#8249; Home</button>
        <div style={{ fontFamily:"'Bebas Neue'", fontSize:22, letterSpacing:1 }}>EDIT SESSION TIME</div>
      </div>

      <div style={{ padding:"12px 20px 0" }}>
        <div style={{ color:"#c8c8e0", fontSize:13.5, textAlign:"center", lineHeight:1.6, marginBottom:16 }}>
          How much time do you have per workout? Your program adjusts the number of exercises to fit.
        </div>
        <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
          {opts.map(([val,label,sub]) => {
            const on = time===val;
            return (
              <button key={val} onClick={()=>setTime(val)} style={{ textAlign:"left", background: on ? "#e8ff00" : "#1a1a26", border:"1px solid " + (on ? "#e8ff00" : "#2a2a3d"), color: on ? "#000" : "#f0f0f8", borderRadius:10, padding:"14px 18px", cursor:"pointer", fontFamily:"'DM Sans'" }}>
                <div style={{ fontFamily:"'Bebas Neue'", fontSize:20, letterSpacing:1 }}>{label}</div>
                <div style={{ fontSize:15, opacity:0.8 }}>{sub}</div>
              </button>
            );
          })}
        </div>

        <button onClick={()=> onSave(time)} disabled={!changed} style={{ width:"100%", marginTop:18, background: changed ? "#e8ff00" : "#2a2a3d", color: changed ? "#000" : "#9898b8", border:"none", borderRadius:12, padding:"16px", cursor: changed?"pointer":"not-allowed", fontFamily:"'Bebas Neue'", letterSpacing:2, fontSize:20 }}>
          SAVE CHANGES
        </button>
      </div>
    </div>
  );
}

function TrainingWeek({ profile, program, cardioPlan, stretchPlan, stepEntries, onPickDay, onEditDays, onEditTime, onChangeProgram, onBack, aiGenerating, onRegenerateAI }) {
  const sched = program.weeklySchedule || [];
  const todayName = DAY_NAMES[new Date().getDay()];
  const todayIdx = sched.findIndex(d => d.day === todayName);
  const trainAccent = (profile && profile.gender === "Female") ? APP_PINK : "#e8ff00";
  const aiEligible = isAIProgramEligible(profile);
  const aiOn = !!(program && program.aiGenerated);
  // Live timeline: factor the client's actual walking into the projection so it
  // tightens (or slips) vs. the at-signup baseline as they log steps.
  const liveSteps = avgDailySteps(stepEntries);
  const baseTl = program.timeline || goalTimeline(profile, profile.deficit || "moderate");
  const liveTl = baseTl ? goalTimeline(profile, profile.deficit || "moderate", undefined, liveSteps) : null;
  const stepTarget = stepTargetFor(profile);
  const aheadDays = (liveTl && baseTl) ? (baseTl.weeks - liveTl.weeks) * 7 : 0;
  return (
    <div style={{ minHeight:"100vh", background:"transparent", paddingBottom:40, position:"relative" }}>
      <style>{GLOBAL_CSS}</style>
      <WatermarkPlain />
      <div style={{ display:"flex", alignItems:"center", gap:12, padding:"16px 5% 8px" }}>
        <button onClick={onBack} style={{ background:"transparent", border:"1px solid #2a2a3d", borderRadius:8, color:"#c8c8e0", padding:"7px 12px", cursor:"pointer", fontSize:14 }}>&#8249; Home</button>
        <div style={{ fontFamily:"'Bebas Neue'", fontSize:22, letterSpacing:1 }}>TRAINING WEEK</div>
      </div>

      <div style={{ padding:"6px 5% 6px", display:"flex", justifyContent:"flex-end", gap:8, flexWrap:"wrap" }}>
        <button onClick={onChangeProgram} style={{ background:"transparent", border:"1px solid "+trainAccent, borderRadius:8, color:trainAccent, padding:"6px 12px", cursor:"pointer", fontSize:12.5, fontFamily:"'DM Sans'", fontWeight:600 }}>Change Program</button>
        <button onClick={onEditTime} style={{ background:"transparent", border:"1px solid #2a2a3d", borderRadius:8, color:trainAccent, padding:"6px 12px", cursor:"pointer", fontSize:12.5, fontFamily:"'DM Sans'", fontWeight:600 }}>Edit Time</button>
        <button onClick={onEditDays} style={{ background:"transparent", border:"1px solid #2a2a3d", borderRadius:8, color:trainAccent, padding:"6px 12px", cursor:"pointer", fontSize:12.5, fontFamily:"'DM Sans'", fontWeight:600 }}>Edit Days</button>
        <button onClick={()=>printProgram(program, profile)} style={{ background:"transparent", border:"1px solid #2a2a3d", borderRadius:8, color:"#c8c8e0", padding:"6px 12px", cursor:"pointer", fontSize:12.5, fontFamily:"'DM Sans'", fontWeight:600 }}>🖨 Print</button>
      </div>

      {aiEligible && (
        <div style={{ padding:"0 5% 8px", display:"flex", alignItems:"center", justifyContent:"space-between", gap:10, flexWrap:"wrap" }}>
          <div style={{ display:"flex", alignItems:"center", gap:7, fontSize:12, color:"#9aa0c0", fontFamily:"'DM Sans'" }}>
            {aiGenerating
              ? (<><span className="ai-pulse" style={{ width:8, height:8, borderRadius:"50%", background:trainAccent, display:"inline-block" }} /> Personalizing your program&hellip;</>)
              : aiOn
                ? (<><span style={{ color:trainAccent, fontWeight:700 }}>&#10022; AI-personalized</span> &middot; built for your goal &amp; level</>)
                : (<>Using the starter template</>)}
          </div>
          <button onClick={onRegenerateAI} disabled={aiGenerating}
            style={{ background:"transparent", border:"1px solid "+(aiGenerating?"#2a2a3d":trainAccent), borderRadius:8, color:aiGenerating?"#6a6a80":trainAccent, padding:"6px 12px", cursor:aiGenerating?"default":"pointer", fontSize:12.5, fontFamily:"'DM Sans'", fontWeight:600 }}>
            {aiGenerating ? "Generating…" : (aiOn ? "Re-personalize with AI" : "Personalize with AI")}
          </button>
        </div>
      )}

      {liveTl && (
        <div style={{ margin:"2px 5% 8px", background:"#16161f", border:"1px solid #2a2a3d", borderRadius:12, padding:"12px 14px" }}>
          <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", gap:12, flexWrap:"wrap" }}>
            <div style={{ minWidth:0 }}>
              <div style={{ color:"#9898b8", fontSize:11, letterSpacing:1 }}>YOUR COMMITMENT</div>
              <div style={{ color:"#f0f0f8", fontSize:14, marginTop:2 }}>
                <b style={{ color:trainAccent }}>{liveTl.human}</b> to your goal &middot; target {liveTl.etaDate}
              </div>
            </div>
            <div style={{ color:"#9898b8", fontSize:11.5, textAlign:"right" }}>
              ~{liveTl.weeklyRate} lb/wk &middot; {liveTl.weeks} wks
            </div>
          </div>
          <div style={{ marginTop:8, paddingTop:8, borderTop:"1px solid #2a2a3d", color:"#9898b8", fontSize:11.5, lineHeight:1.5 }}>
            <span style={{ color:"#3ddc84" }}>🚶 Daily steps target {stepTarget.toLocaleString()}</span>
            {liveSteps == null
              ? " — log your steps; walking more shortens this timeline."
              : aheadDays >= 4
                ? ` — averaging ${liveSteps.toLocaleString()}/day, that's ~${Math.round(aheadDays)} days ahead of pace. Keep it up.`
                : aheadDays <= -4
                  ? ` — averaging ${liveSteps.toLocaleString()}/day, below target; more walking will pull your date in.`
                  : ` — averaging ${liveSteps.toLocaleString()}/day, right on pace.`}
          </div>
        </div>
      )}

      <div style={{ display:"flex", flexDirection:"column", gap:9, padding:"6px 5% 0" }}>
        {sched.map((d,i) => {
          const isToday = i === todayIdx;
          const count = d.workout ? d.workout.length : 0;
          return (
            <button key={i} onClick={() => onPickDay(i)} style={{ textAlign:"left", background:"#1a1a26", border:"1px solid " + (isToday ? trainAccent : "#2a2a3d"), borderRadius:12, padding:"13px 14px", cursor:"pointer", display:"flex", justifyContent:"space-between", alignItems:"center", gap:12 }}>
              <div style={{ minWidth:0, flex:1 }}>
                <div style={{ display:"flex", alignItems:"center", gap:8 }}>
                  <span style={{ fontFamily:"'Bebas Neue'", fontSize:27, letterSpacing:1, color:"#f0f0f8" }}>{d.day}</span>
                  {isToday && <span style={{ background:trainAccent, color:"#000", fontSize:12, fontWeight:700, letterSpacing:1, padding:"2px 5px", borderRadius:4 }}>TODAY</span>}
                </div>
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"baseline", gap:10, marginTop:2 }}>
                  <span style={{ color:trainAccent, fontFamily:"'Bebas Neue'", fontSize:16, letterSpacing:0.5 }}>{d.type}</span>
                  <span style={{ color:"#c8c8e0", fontSize:11.5, whiteSpace:"nowrap" }}>{count} exercises &middot; {d.focus}</span>
                </div>
                {cardioPlanLabel(cardioPlan, DAY_NAMES.indexOf(d.day)) && (
                  <div style={{ color:"#3ddc84", fontSize:11.5, marginTop:2 }}><span style={{ color:"#ff3d3d" }}>❤</span> {cardioPlanLabel(cardioPlan, DAY_NAMES.indexOf(d.day))}</div>
                )}
                {stretchPlanLabel(stretchPlan, DAY_NAMES.indexOf(d.day)) && (
                  <div style={{ color:"#9b5de5", fontSize:11.5, marginTop:2 }}>🧘 {stretchPlanLabel(stretchPlan, DAY_NAMES.indexOf(d.day))}</div>
                )}
              </div>
              <span style={{ color:trainAccent, fontSize:20, flexShrink:0 }}>&#8250;</span>
            </button>
          );
        })}
      </div>
    </div>
  );
}

function ProgramSummary({ profile, program, mealPlan, dietPref, onReset, onBack, onEditPlan }) {
  const accent = "#e8ff00";
  const sched = (program && program.weeklySchedule) || [];
  const nMac = macrosFor(profile, dietPref || profile.dietPref || "mediterranean"); // current nutrition targets
  const DAY_SHORT = ["Su","Mo","Tu","We","Th","Fr","Sa"];
  const trainDays = (profile.trainingDays||[]).sort((a,b)=>a-b).map(d=>DAY_NAMES[d]).join(", ");
  const levelMap = {"Beginner":"I","Intermediate":"II","Advanced":"III","Pro":"IV"};

  const Row = ({label, value, color="#f0f0f8"}) => (
    <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", borderBottom:"1px solid #2a2a3d", paddingBottom:10, marginBottom:10 }}>
      <span style={{ color:"#9898b8", fontSize:17, fontFamily:"'Oswald',sans-serif", letterSpacing:1 }}>{label}</span>
      <span style={{ color, fontFamily:"'Bebas Neue'", fontSize:21, letterSpacing:0.5, textAlign:"right", maxWidth:"60%" }}>{value}</span>
    </div>
  );

  return (
    <div style={{ minHeight:"100vh", background:"transparent", paddingBottom:40, paddingLeft:"5%", paddingRight:"5%", position:"relative" }}>
      <style>{GLOBAL_CSS}</style>
      <WatermarkPlain />

      {/* Header */}
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"16px 0 12px" }}>
        <button onClick={onBack} style={{ background:"transparent", border:"1px solid #2a2a3d", borderRadius:8, color:"#c8c8e0", padding:"7px 12px", cursor:"pointer", fontSize:18 }}>&#8249; Home</button>
        <div style={{ fontFamily:"'Bebas Neue'", fontSize:29, letterSpacing:1 }}>MY PROGRAM</div>
        <button onClick={onReset} style={{ background:"rgba(255,61,61,0.12)", border:"1px solid rgba(255,61,61,0.4)", borderRadius:8, color:"#ff7070", padding:"7px 12px", cursor:"pointer", fontSize:17, fontFamily:"'DM Sans'", fontWeight:600 }}>RESET</button>
      </div>

      {/* Print / Save PDF — same native print sheet as the meal plan */}
      <button onClick={()=>printProgramSummary(program, profile, mealPlan, dietPref || profile.dietPref)} style={{ width:"100%", background:"transparent", border:"1px solid #2a2a3d", borderRadius:12, color:"#c8c8e0", padding:"14px", cursor:"pointer", fontFamily:"'DM Sans'", fontWeight:600, fontSize:16, marginBottom:10 }}>🖨 Print / Save PDF</button>

      {/* Change the commitment: re-opens the Plan & Timeline picker (pace OR deadline). */}
      {onEditPlan && (
        <button onClick={onEditPlan} style={{ width:"100%", background:"rgba(232,255,0,0.08)", border:"1px solid rgba(232,255,0,0.4)", borderRadius:12, color:accent, padding:"14px", cursor:"pointer", fontFamily:"'DM Sans'", fontWeight:700, fontSize:16, marginBottom:14 }}>⏱ Adjust My Pace / Deadline</button>
      )}

      {/* Profile details */}
      <div style={{ background:"#1a1a26", border:"1px solid #2a2a3d", borderRadius:14, padding:"16px 18px", marginBottom:14 }}>
        <div style={{ fontFamily:"'Bebas Neue'", fontSize:21, letterSpacing:1, color:accent, marginBottom:12 }}>PROFILE</div>
        <Row label="NAME"           value={`${profile.firstName || profile.name || ""} ${profile.lastName || ""}`.trim() || "—"} />
        <Row label="GOAL"           value={profile.goal.split("(")[0].trim()} color={accent} />
        <Row label="FOCUS"          value={profile.focus.split("(")[0].trim()} />
        <Row label="FITNESS LEVEL"  value={`Level ${levelMap[profile.fitnessLevel]||"I"} — ${profile.fitnessLevel}`} />
        <Row label="AGE"            value={profile.age ? profile.age+" yrs" : "—"} />
        <Row label="WEIGHT"         value={profile.weight ? profile.weight+" lbs" : "—"} />
        <Row label="HEIGHT"         value={profile.heightFt ? `${profile.heightFt}' ${profile.heightIn||0}"` : "—"} />
        <Row label="ACTIVITY LEVEL" value={profile.activityLevel||"—"} />
        <Row label="SESSION LENGTH" value={profile.sessionTime+" min"} />
        <Row label="TRAINING DAYS"  value={trainDays} />
      </div>

      {/* Weekly schedule */}
      <div style={{ background:"#1a1a26", border:"1px solid #2a2a3d", borderRadius:14, padding:"16px 18px", marginBottom:14 }}>
        <div style={{ fontFamily:"'Bebas Neue'", fontSize:21, letterSpacing:1, color:accent, marginBottom:12 }}>WEEKLY SCHEDULE</div>
        {sched.map((d,i) => (
          <div key={i} style={{ borderBottom:"1px solid #2a2a3d", paddingBottom:10, marginBottom:10 }}>
            <div style={{ fontFamily:"'Bebas Neue'", fontSize:23, letterSpacing:1 }}>{d.day}</div>
            <div style={{ color:accent, fontSize:18, fontFamily:"'Bebas Neue'", letterSpacing:0.5 }}>{d.type}</div>
            {d.workout && d.workout.length > 0 && (
              <div style={{ marginTop:4, display:"flex", flexWrap:"wrap", gap:4 }}>
                {d.workout.map((ex,j) => (
                  <span key={j} style={{ background:"#12121a", border:"1px solid #2a2a3d", borderRadius:6, padding:"3px 9px", fontSize:15, color:"#c8c8e0", fontFamily:"'DM Sans'" }}>{ex.exercise}</span>
                ))}
              </div>
            )}
          </div>
        ))}
      </div>

      {/* Nutrition + Meal Plan */}
      <div style={{ background:"#1a1a26", border:"1px solid #2a2a3d", borderRadius:14, padding:"16px 18px", marginBottom:14 }}>
        <div style={{ fontFamily:"'Bebas Neue'", fontSize:21, letterSpacing:1, color:accent, marginBottom:12 }}>NUTRITION</div>
        <Row label="DIET STYLE"   value={(dietPref || profile.dietPref || "mediterranean")} color={accent} />
        <Row label="DAILY CALORIES" value={`${nMac.dailyCalories} cal`} />
        <Row label="PROTEIN"      value={nMac.protein} />
        <Row label="CARBS"        value={nMac.carbs} />
        <Row label="FATS"         value={nMac.fats} />
        {profile.bodyFat ? <Row label="BODY FAT" value={profile.bodyFat+"%"} /> : null}

        {mealPlan && Array.isArray(mealPlan.meals) && mealPlan.meals.length > 0 ? (
          <div style={{ marginTop:14 }}>
            <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:10 }}>
              <span style={{ fontFamily:"'Bebas Neue'", fontSize:20, letterSpacing:1, color:"#dcdcf0" }}>✨ AI MEAL PLAN</span>
              {mealPlan.totals && <span style={{ fontSize:15, color:"#9898b8" }}>{mealPlan.totals.cal} cal · {mealPlan.totals.protein}p · {mealPlan.totals.carbs}c · {mealPlan.totals.fats}f</span>}
            </div>
            {mealPlan.meals.map((ml,mi)=>(
              <div key={mi} style={{ marginBottom:10 }}>
                <div style={{ marginBottom:4 }}>
                  <div style={{ fontFamily:"'DM Sans'", fontSize:14, letterSpacing:1, color:"#9898b8", textTransform:"uppercase", fontWeight:600 }}>{ml.slot}</div>
                  {ml.name && <div style={{ fontFamily:"'Bebas Neue'", fontSize:20, letterSpacing:0.5, color:accent }}>{ml.name}</div>}
                </div>
                {(ml.items||[]).map((it,ii)=>(
                  <div key={ii} style={{ display:"flex", justifyContent:"space-between", fontSize:16, color:"#c8c8e0", padding:"2px 0" }}>
                    <span>{it.food} <span style={{color:"#74748a"}}>· {it.grams}g</span></span>
                    <span style={{ color:"#9898b8", whiteSpace:"nowrap", marginLeft:8 }}>{it.cal}c · {it.protein}p</span>
                  </div>
                ))}
              </div>
            ))}
          </div>
        ) : (
          <div style={{ marginTop:12, fontSize:16, color:"#74748a", lineHeight:1.5 }}>No AI meal plan saved yet — generate one in Nutrition → Generate Meal Plan, tap “Use This Plan,” and it'll appear here.</div>
        )}
      </div>

      {/* Reset notice */}
      <div style={{ background:"rgba(255,61,61,0.07)", border:"1px solid rgba(255,61,61,0.25)", borderRadius:12, padding:"12px 16px" }}>
        <div style={{ color:"#ff7070", fontSize:16, lineHeight:1.6 }}>
          ⚠ Tap <strong>RESET</strong> to clear your profile and rebuild your program from scratch. Your workout history will be preserved.
        </div>
      </div>
    </div>
  );
}


