function getMealSuggestion(dietId, dayOfWeek, slot) {
  const plans = (MEAL_SUGGESTIONS[dietId] || MEAL_SUGGESTIONS.mediterranean);
  const day = plans[dayOfWeek % plans.length];
  return day[slot] || null;
}

